const ActiveSession: React.FC<ActiveSessionProps> = ({ scenario, avatarConfig, sessionSettings, initialTranscript, onEndSession }) => {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.CONNECTING);
  const [transcripts, setTranscripts] = useState<TranscriptItem[]>(initialTranscript || []);
  const [initialCount] = useState(initialTranscript?.length || 0);

  const volumeRef = useRef({ input: 0, output: 0 });

  const [error, setError] = useState<string | null>(null);
  const [startTime] = useState<number>(Date.now());
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [pronunciationTip, setPronunciationTip] = useState<string | null>(null);

  // Real-time Fluency Stats
  // Fix: Explicitly type fillerCount and awkwardPauseCount as number to avoid 'unknown' inference issues.
  const [fillerCount, setFillerCount] = useState<number>(0);
  const [awkwardPauseCount, setAwkwardPauseCount] = useState<number>(0);
  const [showPauseAlert, setShowPauseAlert] = useState(false);
  const pauseTimerRef = useRef<number | null>(null);
  const lastSpeakTimeRef = useRef<number>(Date.now());

  const [currentEmotion, setCurrentEmotion] = useState<string>('Neutral');
  const [currentIntent, setCurrentIntent] = useState<string>('Socializing');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const emotionCounts = useRef<Record<string, number>>({});
  const intentCounts = useRef<Record<string, number>>({});

  const clientRef = useRef<LiveClient | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isUserAtBottom = useRef(true); 
  const [autoScrollEnabled, setAutoScrollEnabled] = useState(true);
  const mountedRef = useRef(true);

  // Awkward Pause Detection Logic
  useEffect(() => {
    const PAUSE_THRESHOLD = 3500; // 3.5 seconds

    const checkPause = () => {
      if (status !== ConnectionStatus.CONNECTED || isSpeaking || isUserSpeaking) {
        setShowPauseAlert(false);
        lastSpeakTimeRef.current = Date.now();
        return;
      }

      const silenceDuration = Date.now() - lastSpeakTimeRef.current;

      if (silenceDuration > PAUSE_THRESHOLD) {
        if (!showPauseAlert) {
            setShowPauseAlert(true);
            setAwkwardPauseCount(prev => prev + 1);
        }
      }
    };

    const interval = setInterval(checkPause, 500);
    return () => clearInterval(interval);
  }, [status, isSpeaking, isUserSpeaking, showPauseAlert]);

  const displayedAvatarConfig = useMemo(() => {
    const voiceMeta = getVoiceMetadata(sessionSettings.voiceName);
    const targetGender = (voiceMeta.gender || 'Male').toLowerCase() as 'male' | 'female';
    const adjustedConfig = { ...avatarConfig };

    if (adjustedConfig.gender !== targetGender) {
        adjustedConfig.gender = targetGender;
        if (targetGender === 'male') {
            if (['long', 'bun'].includes(adjustedConfig.hairStyle)) {
                adjustedConfig.hairStyle = 'short';
            }
        } else {
             if (adjustedConfig.hairStyle === 'bald') {
                 adjustedConfig.hairStyle = 'short';
             }
        }
    }
    return adjustedConfig;
  }, [avatarConfig, sessionSettings.voiceName]);

  const handleScroll = () => {
    if (!scrollRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
    const distanceToBottom = scrollHeight - scrollTop - clientHeight;
    isUserAtBottom.current = distanceToBottom < 100;
  };

  const toggleAutoScroll = () => {
      setAutoScrollEnabled(prev => {
          const next = !prev;
          if (next && scrollRef.current) {
              scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
              isUserAtBottom.current = true;
          }
          return next;
      });
  };

  useLayoutEffect(() => {
    if (scrollRef.current && autoScrollEnabled && isUserAtBottom.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [transcripts, autoScrollEnabled]);

  const handleTranscript = useCallback((text: string, isUser: boolean, isFinal: boolean) => {
    if (!mountedRef.current) return;

    if (isUser) {
        setIsUserSpeaking(true);
        lastSpeakTimeRef.current = Date.now();
        if ((window as any).userSpeakTimeout) clearTimeout((window as any).userSpeakTimeout);
        (window as any).userSpeakTimeout = setTimeout(() => setIsUserSpeaking(false), 800);

        // Real-time Filler Word Counting
        const matches = text.match(FILLER_WORD_REGEX);
        if (matches) {
            setFillerCount(prev => prev + matches.length);
        }
    }

    setTranscripts(prev => {
        const last = prev[prev.length - 1];
        if (last && last.role === (isUser ? 'user' : 'model')) {
            const updatedLast = { ...last, text: last.text + text };
            return [...prev.slice(0, -1), updatedLast];
        }
        return [...prev, { 
            id: Date.now().toString() + Math.random().toString().slice(2,6),
            role: isUser ? 'user' : 'model', 
            text, 
            timestamp: Date.now() 
        }];
    });

    if (!isUser) {
        setIsSpeaking(true);
        if ((window as any).speakingTimeout) clearTimeout((window as any).speakingTimeout);
        (window as any).speakingTimeout = setTimeout(() => setIsSpeaking(false), 500); 
    }
  }, []);

  const handleGrounding = useCallback((metadata: any) => {
    if (!mountedRef.current) return;
    if (metadata?.groundingChunks) {
        const newSources = metadata.groundingChunks.map((chunk: any) => chunk.web).filter((web: any) => web);
        if (newSources.length > 0) {
            setTranscripts(prev => {
                const last = prev[prev.length - 1];
                if (last && last.role === 'model') {
                     const existing = last.sources || [];
                     const existingUris = new Set(existing.map(s => s.uri));
                     const uniqueNew = newSources.filter((s: any) => !existingUris.has(s.uri));
                     if (uniqueNew.length === 0) return prev;
                     return [...prev.slice(0, -1), { ...last, sources: [...existing, ...uniqueNew] }];
                }
                return prev;
            });
        }
    }
  }, []);

  useEffect(() => {
    const lastModelItem = transcripts.filter(t => t.role === 'model').pop();
    if (lastModelItem) {
        const match = lastModelItem.text.match(ANALYSIS_REGEX);
        if (match) {
            const emotion = match[1];
            const intent = match[2];
            if (emotion && emotion !== currentEmotion) {
                setCurrentEmotion(emotion);
                emotionCounts.current[emotion] = (emotionCounts.current[emotion] || 0) + 1;
            }
            if (intent && intent !== currentIntent) {
                setCurrentIntent(intent);
                intentCounts.current[intent] = (intentCounts.current[intent] || 0) + 1;
            }
        }
        const tipMatch = lastModelItem.text.match(/Tip:\s*(.*?)(\.|$)/i);
        if (tipMatch) {
            const tipText = tipMatch[1].trim();
            setPronunciationTip(tipText);
            if ((window as any).tipTimeout) clearTimeout((window as any).tipTimeout);
            (window as any).tipTimeout = setTimeout(() => setPronunciationTip(null), 8000);
        }
    }
  }, [transcripts, currentEmotion, currentIntent]);

  useEffect(() => {
    const initSession = async () => {
      try {
        const adaptedInstruction = getAdaptedSystemInstruction(scenario, sessionSettings, initialTranscript);
        clientRef.current = new LiveClient(
            process.env.API_KEY || '',
            handleTranscript,
            (inVol, outVol) => { 
              if (mountedRef.current) {
                if (inVol < 0.001) {
                    volumeRef.current = { input: 0, output: outVol };
                    return;
                }
                const boostedInput = Math.min(Math.pow(inVol, 0.35), 1.0);
                volumeRef.current = { input: boostedInput, output: outVol };
              } 
            },
            handleGrounding,
            () => { if (mountedRef.current) setStatus(ConnectionStatus.DISCONNECTED); },
            (err) => { 
                console.error(err);
                if (mountedRef.current) {
                    setError("Microphone access denied or connection failed."); 
                    setStatus(ConnectionStatus.ERROR);
                }
            }
        );
        const voice = sessionSettings.voiceName || scenario.voiceName;
        await clientRef.current.connect(adaptedInstruction, voice);
        if (mountedRef.current) setStatus(ConnectionStatus.CONNECTED);
      } catch (e) {
        if (mountedRef.current) {
            setError("Failed to initialize AI session.");
            setStatus(ConnectionStatus.ERROR);
        }
      }
    };
    initSession();
    return () => {
      mountedRef.current = false;
      clientRef.current?.disconnect();
    };
  }, [scenario, handleTranscript, sessionSettings, initialTranscript, handleGrounding]);

  const saveSession = async () => {
    if (clientRef.current) clientRef.current.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    const endTime = Date.now();
    const durationSeconds = (endTime - startTime) / 1000;
    const report: SessionReport = {
        durationSeconds,
        fillerWordCount: fillerCount, 
        awkwardPauseCount,
        fillerWordsPerMinute: durationSeconds > 0 ? (fillerCount / (durationSeconds / 60)) : 0,
        transcript: transcripts,
        dominantEmotion: currentEmotion,
        dominantIntent: currentIntent,
        paceWPM: 0,
    };
    onEndSession(report, true);
  };

  const endSession = async () => {
    if (isAnalyzing) return;
    clientRef.current?.disconnect();
    setIsAnalyzing(true);
    setStatus(ConnectionStatus.DISCONNECTED);
    const endTime = Date.now();
    const durationSeconds = (endTime - startTime) / 1000;
    const userText = transcripts.filter(t => t.role === 'user').map(t => t.text).join(' ');
    const wordCount = userText.trim().split(/\s+/).length;
    const paceWPM = durationSeconds > 0 ? Math.round(wordCount / (durationSeconds / 60)) : 0;
    let dominantEmo = 'Neutral';
    let maxEmoCount = 0;
    Object.entries(emotionCounts.current).forEach(([emo, count]) => {
        if (count > maxEmoCount) {
            maxEmoCount = count;
            dominantEmo = emo;
        }
    });
    let dominantIntent = 'Socializing';
    let maxIntentCount = 0;
    Object.entries(intentCounts.current).forEach(([int, count]) => {
        if (count > maxIntentCount) {
            maxIntentCount = count;
            dominantIntent = int;
        }
    });
    const analysis = await generateSessionAnalysis(transcripts, scenario.title, process.env.API_KEY || '');
    const report: SessionReport = {
        durationSeconds,
        fillerWordCount: fillerCount,
        awkwardPauseCount,
        fillerWordsPerMinute: durationSeconds > 0 ? (fillerCount / (durationSeconds / 60)) : 0,
        transcript: transcripts,
        dominantEmotion: dominantEmo,
        dominantIntent: dominantIntent,
        paceWPM,
        ...analysis
    };
    onEndSession(report, false);
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden relative">

      {isAnalyzing && (
        <div className="absolute inset-0 z-50 bg-slate-900/60 backdrop-blur-sm flex flex-col items-center justify-center text-white animate-fade-in">
           <div className="w-16 h-16 border-4 border-brand-400 border-t-transparent rounded-full animate-spin mb-4"></div>
           <h3 className="text-xl font-bold">Generating Report</h3>
           <p className="text-brand-100 text-sm">Analyzing grammar, fluency, and tone...</p>
        </div>
      )}

      {/* Header */}
      <div className={`p-4 border-b border-slate-100 flex items-center justify-between ${scenario.color} bg-opacity-10 shrink-0 z-20 relative bg-white`}>
        <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-full ${scenario.color} text-white flex items-center justify-center`}>
                <i className={`fa-solid ${scenario.icon}`}></i>
            </div>
            <div>
                <h3 className="font-bold text-slate-900 leading-tight">{scenario.title}</h3>
                <div className="flex items-center gap-2 text-xs text-slate-500">
                    <span className="flex items-center gap-1">
                        <div className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-green-500 animate-pulse' : 'bg-slate-300'}`}></div>
                        {status === ConnectionStatus.CONNECTED ? 'Live' : status}
                    </span>
                    <span>•</span>
                    <span className="capitalize font-bold text-brand-600">{sessionSettings.language}</span>
                </div>
            </div>
        </div>
        <div className="flex items-center gap-2">
            {/* Live Metrics Overlay Mini */}
            <div className="hidden sm:flex items-center gap-2 mr-4 bg-white border border-slate-200 px-3 py-1 rounded-full shadow-sm">
                <div className="flex items-center gap-1.5 text-[10px] font-bold">
                    <span className="text-slate-400">FILLERS:</span>
                    <span className={`${fillerCount > 5 ? 'text-orange-500' : 'text-brand-600'} transition-all`}>{fillerCount}</span>
                </div>
                <div className="w-px h-3 bg-slate-200"></div>
                <div className="flex items-center gap-1.5 text-[10px] font-bold">
                    <span className="text-slate-400">PAUSES:</span>
                    <span className={`${awkwardPauseCount > 3 ? 'text-red-500' : 'text-slate-600'}`}>{awkwardPauseCount}</span>
                </div>
            </div>

            <button
                onClick={saveSession}
                disabled={isAnalyzing}
                className="bg-white text-slate-600 px-3 py-2 rounded-lg text-xs font-bold hover:bg-slate-50 transition-colors disabled:opacity-50 border border-slate-200 flex items-center gap-2"
            >
                <i className="fa-solid fa-floppy-disk"></i>
                Save
            </button>
            <button 
                onClick={endSession}
                disabled={isAnalyzing}
                className="bg-red-50 text-red-600 px-4 py-2 rounded-lg text-xs font-bold hover:bg-red-100 transition-colors disabled:opacity-50 flex items-center gap-2"
            >
                <i className="fa-solid fa-flag-checkered"></i>
                Finish
            </button>
        </div>
      </div>

      {/* Main Body */}
      <div className="flex-1 relative flex flex-col min-h-0">

         <div className="absolute inset-0 z-0 flex items-center justify-center p-8 opacity-20 md:opacity-100 pointer-events-none overflow-hidden">
            <div className="w-64 h-64 md:w-80 md:h-80 relative">
               {isSpeaking && (
                 <>
                   <div className="absolute inset-0 border-4 border-brand-200 rounded-full animate-ping opacity-20"></div>
                   <div className="absolute -inset-4 border-4 border-brand-100 rounded-full animate-pulse opacity-30"></div>
                 </>
               )}
               <LiveAvatar config={displayedAvatarConfig} volumeRef={volumeRef} isSpeaking={isSpeaking} />
            </div>
         </div>

         {/* Pause Alert Overlay */}
         {showPauseAlert && status === ConnectionStatus.CONNECTED && (
             <div className="absolute top-20 left-1/2 -translate-x-1/2 z-40 bg-red-500 text-white px-4 py-2 rounded-full shadow-lg font-bold text-xs animate-bounce flex items-center gap-2 pointer-events-none">
                <i className="fa-solid fa-hourglass-start animate-spin"></i>
                AWKWARD PAUSE DETECTED
             </div>
         )}

         {/* Live Status Tags */}
         <div className="absolute top-4 w-full px-4 flex justify-between items-start z-20 pointer-events-none">
            <div className={`backdrop-blur-md border shadow-sm px-3 py-1.5 rounded-full flex items-center gap-2 transition-all ${
                currentEmotion === 'Confident' || currentEmotion === 'Excited' ? 'bg-green-50/90 border-green-200 text-green-700' :
                currentEmotion === 'Hesitant' || currentEmotion === 'Nervous' ? 'bg-orange-50/90 border-orange-200 text-orange-700' :
                'bg-slate-50/90 border-slate-200 text-slate-600'
            }`}>
                <div className="text-[10px] uppercase font-bold tracking-wider opacity-70">Emotion</div>
                <div className="text-xs font-bold flex items-center gap-1">
                    <i className={`fa-solid ${
                        currentEmotion === 'Confident' ? 'fa-bolt' : 
                        currentEmotion === 'Hesitant' ? 'fa-circle-pause' : 
                        currentEmotion === 'Excited' ? 'fa-face-laugh-beam' : 'fa-face-meh'
                    }`}></i>
                    {currentEmotion}
                </div>
            </div>

            <div className="backdrop-blur-md bg-blue-50/90 border border-blue-200 text-blue-700 shadow-sm px-3 py-1.5 rounded-full flex items-center gap-2 transition-all">
                <div className="text-[10px] uppercase font-bold tracking-wider opacity-70">Intent</div>
                <div className="text-xs font-bold flex items-center gap-1">
                     <i className="fa-solid fa-bullseye"></i>
                    {currentIntent}
                </div>
            </div>
         </div>

         <div 
           ref={scrollRef}
           onScroll={handleScroll}
           className="relative z-10 flex-1 overflow-y-auto p-6 space-y-4"
           style={{ maskImage: 'linear-gradient(to bottom, transparent 0%, black 15%)' }}
         >
            <div className="h-4"></div> 
            {transcripts.map((t, idx) => (
                <TranscriptMessage 
                    key={t.id} 
                    item={t} 
                    scenarioColor={scenario.color}
                    isInitialResumeMarker={idx === initialCount && initialCount > 0} 
                />
            ))}
         </div>

         <div className="absolute bottom-28 right-6 z-30">
            <button
                onClick={toggleAutoScroll}
                className={`w-10 h-10 rounded-full shadow-md border flex items-center justify-center transition-all ${
                    autoScrollEnabled ? 'bg-white text-brand-600 border-brand-200' : 'bg-slate-800 text-white border-slate-700'
                }`}
            >
                <i className={`fa-solid ${autoScrollEnabled ? 'fa-lock' : 'fa-lock-open'}`}></i>
            </button>
         </div>

         <div className="h-24 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col items-center justify-center relative z-20 shrink-0">
            {pronunciationTip && <PronunciationFeedback tip={pronunciationTip} />}
            {error ? (
                <div className="text-red-500 font-medium text-sm flex items-center gap-2">
                    <i className="fa-solid fa-triangle-exclamation"></i>
                    {error}
                </div>
            ) : (
                <>
                    <LiveVisualizer volumeRef={volumeRef} isActive={status === ConnectionStatus.CONNECTED} />
                    <p className="text-xs text-slate-400 mt-2 font-medium">
                        {status === ConnectionStatus.CONNECTED ? 'Listening...' : 'Connecting...'}
                    </p>
                </>
            )}
         </div>
      </div>
    </div>
  );
};

export default ActiveSession;

import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createBlob, decode, decodeAudioData } from './audioUtils';
import { AUDIO_SAMPLE_RATE_INPUT, AUDIO_SAMPLE_RATE_OUTPUT } from '../constants';

export type TranscriptCallback = (text: string, isUser: boolean, isFinal: boolean) => void;
export type VolumeCallback = (inputVolume: number, outputVolume: number) => void;
export type GroundingCallback = (metadata: any) => void;

export class LiveClient {
  private ai: GoogleGenAI;
  private model: string = 'gemini-2.5-flash-native-audio-preview-09-2025';
  private inputAudioContext: AudioContext | null = null;
  private outputAudioContext: AudioContext | null = null;
  private mediaStream: MediaStream | null = null;
  private processor: ScriptProcessorNode | null = null;
  private source: MediaStreamAudioSourceNode | null = null;

  private inputAnalyser: AnalyserNode | null = null;
  private outputAnalyser: AnalyserNode | null = null;
  private animationFrameId: number | null = null;

  private nextStartTime: number = 0;
  private activeSources: Set<AudioBufferSourceNode> = new Set();

  // Callbacks
  private onTranscript: TranscriptCallback;
  private onVolume: VolumeCallback;
  private onGrounding: GroundingCallback;
  private onClose: () => void;
  private onError: (err: Error) => void;

  private sessionPromise: Promise<any> | null = null;

  constructor(
    apiKey: string, 
    onTranscript: TranscriptCallback, 
    onVolume: VolumeCallback,
    onGrounding: GroundingCallback,
    onClose: () => void,
    onError: (err: Error) => void
  ) {
    this.ai = new GoogleGenAI({ apiKey });
    this.onTranscript = onTranscript;
    this.onVolume = onVolume;
    this.onGrounding = onGrounding;
    this.onClose = onClose;
    this.onError = onError;
  }

  public async connect(systemInstruction: string, voiceName: string) {
    try {
      this.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: AUDIO_SAMPLE_RATE_INPUT,
      });
      this.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: AUDIO_SAMPLE_RATE_OUTPUT,
      });

      this.mediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Setup Input Analysis
      this.inputAnalyser = this.inputAudioContext.createAnalyser();
      this.inputAnalyser.fftSize = 256;
      this.inputAnalyser.smoothingTimeConstant = 0.1;

      // Setup Output Analysis
      this.outputAnalyser = this.outputAudioContext.createAnalyser();
      this.outputAnalyser.fftSize = 256;
      this.outputAnalyser.smoothingTimeConstant = 0.1;
      this.outputAnalyser.connect(this.outputAudioContext.destination);

      const promise = this.ai.live.connect({
        model: this.model,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName } },
          },
          systemInstruction: systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          tools: [{ googleSearch: {} }]
        },
        callbacks: {
          onopen: () => {
            this.startAudioInput(promise);
            this.startAnalysisLoop();
          },
          onmessage: (msg: LiveServerMessage) => this.handleMessage(msg),
          onclose: () => {
            this.onClose();
          },
          onerror: (err: ErrorEvent) => {
            this.onError(new Error("Connection error: " + err.message));
          }
        }
      });

      this.sessionPromise = promise;
    } catch (error) {
      this.onError(error as Error);
    }
  }

  private startAnalysisLoop() {
    const dataArray = new Uint8Array(128);

    const analyze = () => {
      let inputVol = 0;
      let outputVol = 0;

      // Analyze Input
      if (this.inputAnalyser) {
        this.inputAnalyser.getByteTimeDomainData(dataArray);
        let sum = 0;
        for(let i = 0; i < dataArray.length; i++) {
          const x = (dataArray[i] - 128) / 128.0;
          sum += x * x;
        }
        inputVol = Math.sqrt(sum / dataArray.length);
      }

      // Analyze Output
      if (this.outputAnalyser) {
        this.outputAnalyser.getByteTimeDomainData(dataArray);
        let sum = 0;
        for(let i = 0; i < dataArray.length; i++) {
          const x = (dataArray[i] - 128) / 128.0;
          sum += x * x;
        }
        outputVol = Math.sqrt(sum / dataArray.length);
      }

      this.onVolume(inputVol, outputVol);
      this.animationFrameId = requestAnimationFrame(analyze);
    };

    analyze();
  }

  private startAudioInput(sessionPromise: Promise<any>) {
    if (!this.inputAudioContext || !this.mediaStream || !this.inputAnalyser) return;

    this.source = this.inputAudioContext.createMediaStreamSource(this.mediaStream);
    this.processor = this.inputAudioContext.createScriptProcessor(4096, 1, 1);

    this.processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);
      const pcmBlob = createBlob(inputData);
      sessionPromise.then((session) => {
        session.sendRealtimeInput({ media: pcmBlob });
      });
    };

    this.source.connect(this.inputAnalyser);
    this.inputAnalyser.connect(this.processor);
    this.processor.connect(this.inputAudioContext.destination);
  }

  private async handleMessage(message: LiveServerMessage) {
    // 1. Handle Audio Output
    const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData && this.outputAudioContext) {
      this.playAudio(audioData);
    }

    // 2. Handle User Transcription
    const userTranscript = message.serverContent?.inputTranscription?.text;
    if (userTranscript) {
      this.onTranscript(userTranscript, true, !!message.serverContent?.turnComplete);
    }

    // 3. Handle Model Transcription
    const modelTranscript = message.serverContent?.outputTranscription?.text;
    if (modelTranscript) {
       this.onTranscript(modelTranscript, false, !!message.serverContent?.turnComplete);
    }

    // 4. Handle Grounding (Search Results)
    const groundingMetadata = message.serverContent?.groundingMetadata;
    if (groundingMetadata) {
      this.onGrounding(groundingMetadata);
    }

    // 5. Handle Interruption
    if (message.serverContent?.interrupted) {
      this.stopPlayback();
    }
  }

  private async playAudio(base64Data: string) {
    if (!this.outputAudioContext || !this.outputAnalyser) return;

    const bytes = decode(base64Data);
    const buffer = await decodeAudioData(bytes, this.outputAudioContext, AUDIO_SAMPLE_RATE_OUTPUT, 1);

    this.nextStartTime = Math.max(this.nextStartTime, this.outputAudioContext.currentTime);

    const source = this.outputAudioContext.createBufferSource();
    source.buffer = buffer;

    // Connect to Analyser for visualizer, which is already connected to destination
    source.connect(this.outputAnalyser);

    source.addEventListener('ended', () => {
      this.activeSources.delete(source);
    });

    source.start(this.nextStartTime);
    this.nextStartTime += buffer.duration;
    this.activeSources.add(source);
  }

  private stopPlayback() {
    this.activeSources.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    this.activeSources.clear();
    this.nextStartTime = this.outputAudioContext?.currentTime || 0;
  }

  public async disconnect() {
    if (this.animationFrameId) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = null;
    }

    // Close the live session connection
    if (this.sessionPromise) {
      try {
          const session = await this.sessionPromise;
          session.close();
      } catch (e) {
          console.debug('Error closing session', e);
      }
      this.sessionPromise = null;
    }

    this.stopPlayback();

    if (this.processor) {
      this.processor.disconnect();
      this.processor = null;
    }
    if (this.source) {
      this.source.disconnect();
      this.source = null;
    }
    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach(track => track.stop());
      this.mediaStream = null;
    }
    if (this.inputAudioContext) {
      await this.inputAudioContext.close();
      this.inputAudioContext = null;
    }
    if (this.outputAudioContext) {
      await this.outputAudioContext.close();
      this.outputAudioContext = null;
    }

    this.onVolume(0, 0);
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { TranscriptItem, SessionReport } from "../types";

export const generateSessionAnalysis = async (
  transcript: TranscriptItem[],
  scenarioTitle: string,
  apiKey: string
): Promise<Partial<SessionReport>> => {
  const ai = new GoogleGenAI({ apiKey });

  // Extract only user text for analysis to save tokens and focus context
  const userItems = transcript.filter(t => t.role === 'user');
  const userText = userItems.map(t => t.text).join(' ');

  // If there's not enough data, return a neutral/empty report
  if (!userText || userText.trim().length < 15) {
      return {
          fluencyScore: 50,
          vocabularyScore: 50,
          grammarCorrections: [],
          confidenceTips: ["Try speaking more in the next session to receive detailed AI feedback."]
      };
  }

  const prompt = `
    You are an expert language and confidence coach. Analyze the following user transcript from a practice session titled '${scenarioTitle}'.

    User Transcript: "${userText}"

    Your goal is to provide constructive feedback.

    Tasks:
    1. Grammar & Phrasing: Identify up to 3 specific grammatical errors or awkward phrasings. 
       - Provide the original text.
       - Provide a corrected version.
       - Provide a concise explanation of the rule violated (e.g., "Subject-Verb Agreement", "Incorrect Tense", "Wrong Preposition").
    2. Fluency Score (0-100): Rate based on natural flow, sentence structure, and coherence (ignoring simple filler words which are counted separately).
    3. Vocabulary Score (0-100): Rate based on lexical variety and appropriateness for the scenario.
    4. Confidence Tips: Provide 2 specific, actionable tips to improve the user's tone or delivery based on the text content.
  `;

  try {
      // Always use 'gemini-3-flash-preview' for basic text tasks like feedback analysis
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              fluencyScore: { type: Type.NUMBER },
              vocabularyScore: { type: Type.NUMBER },
              grammarCorrections: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    original: { type: Type.STRING },
                    correction: { type: Type.STRING },
                    explanation: { type: Type.STRING, description: "A concise rule or reason e.g. 'Subject-Verb Agreement'" }
                  }
                }
              },
              confidenceTips: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          }
        }
      });

      const jsonText = response.text;
      if (!jsonText) throw new Error("Empty response from analysis model");

      return JSON.parse(jsonText);
  } catch (e) {
      console.error("Analysis failed", e);
      // Fallback in case of API error
      return {
          fluencyScore: 0,
          vocabularyScore: 0,
          grammarCorrections: [],
          confidenceTips: ["Analysis could not be generated at this time."]
      };
  }
};

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Resource, UserStats, SessionHistoryItem } from "../types";
import { pcmToWav, decode } from "./audioUtils";

const SCENARIO_COLORS = ['bg-blue-500', 'bg-red-500', 'bg-green-500', 'bg-yellow-500', 'bg-purple-500', 'bg-pink-500', 'bg-indigo-500', 'bg-orange-500', 'bg-teal-500', 'bg-slate-800'];
const ICONS = {
  video: 'fa-play',
  article: 'fa-newspaper',
  podcast: 'fa-headphones'
};

export const fetchDailyRecommendations = async (
  stats: UserStats, 
  history: SessionHistoryItem[], 
  apiKey: string
): Promise<Resource[]> => {
  const ai = new GoogleGenAI({ apiKey });
  const today = new Date().toDateString();

  // 1. Analyze Context from History
  const recentHistory = history.slice(0, 5); // Analyze last 5 sessions
  const lastSession = history.length > 0 ? history[0] : null;
  const lastTopic = lastSession ? lastSession.scenarioTitle : "General Communication";

  // Identify Weaknesses dynamically
  const improvementAreas = [];

  // Filler words check
  const avgFillers = recentHistory.length > 0 
      ? recentHistory.reduce((acc, h) => acc + h.report.fillerWordCount, 0) / recentHistory.length
      : 0;
  if (avgFillers > 6) improvementAreas.push("Reducing filler words (um, uh)");

  // Confidence check
  const nervousCount = recentHistory.filter(h => h.report.dominantEmotion === 'Nervous' || h.report.dominantEmotion === 'Hesitant').length;
  if (nervousCount > 0) improvementAreas.push("Boosting speaking confidence");

  // Vocabulary check (heuristic based on difficulty)
  const basicSessions = recentHistory.filter(h => h.settings.difficulty === 'beginner').length;
  if (basicSessions > 2) improvementAreas.push("Expanding vocabulary complexity");

  // Specific Scenario Focus
  const interviewFocus = recentHistory.some(h => h.scenarioId === 'interview');
  if (interviewFocus) improvementAreas.push("Professional interview responses");

  // Default if no specific data
  if (improvementAreas.length === 0) improvementAreas.push("Advanced conversational nuances");

  const prompt = `
    Today is ${today}.
    Generate 3 distinct, daily coaching resources for a user learning languages and communication skills.

    User Profile:
    - Current Level: ${stats.level} (XP: ${stats.xp})
    - Last Practice Session: "${lastTopic}"
    - Targeted Improvement Areas: ${improvementAreas.join(', ')}.

    Task:
    Return a JSON array of 3 resources. 
    Ensure the titles and descriptions are unique to *today* and tailored to the user's recent activity.
    Vary the topics: include one specific technique, one mindset/confidence tip, and one practice drill.

    Required Types:
    1. 'video' (A visual lesson or drill).
    2. 'podcast' (A conversation or interview).
    3. 'article' (A guide or tip sheet).

    Schema per item:
    - title (String): Engaging and specific.
    - description (String): 1-2 sentences summarizing the value.
    - type (String): 'video', 'podcast', or 'article'.
    - category (String): e.g., "Fluency", "Social Skills", "Business", "Vocab".
    - duration (String): e.g., "3 min", "6 min".
    - xp (Number): Reward amount (30-100).
  `;

  try {
    // Basic Text Task: Use gemini-3-flash-preview
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    title: { type: Type.STRING },
                    description: { type: Type.STRING },
                    type: { type: Type.STRING, enum: ['video', 'podcast', 'article'] },
                    category: { type: Type.STRING },
                    duration: { type: Type.STRING },
                    xp: { type: Type.NUMBER }
                }
            }
        }
      }
    });

    const data = JSON.parse(response.text || '[]');

    return data.map((item: any, index: number) => ({
      ...item,
      id: `daily_${Date.now()}_${index}`,
      icon: ICONS[item.type as keyof typeof ICONS] || 'fa-star',
      imageColor: SCENARIO_COLORS[Math.floor(Math.random() * SCENARIO_COLORS.length)],
      isGenerated: true
    }));

  } catch (e) {
    console.error("Failed to generate recommendations", e);
    // Return empty to allow fallback in UI or fallback resources
    return [];
  }
};

export const generateResourceContent = async (resource: Resource, apiKey: string): Promise<Resource['content']> => {
    const ai = new GoogleGenAI({ apiKey });
    const content: Resource['content'] = {};

    // Complexity modifier based on XP rewards (proxy for user level relevance)
    const complexityLevel = resource.xp > 70 ? "Advanced/Professional" : "Beginner/Intermediate";

    try {
        if (resource.type === 'article') {
            const prompt = `
            Write a high-quality, actionable short article titled "${resource.title}".
            Topic Category: ${resource.category}.
            Target Audience: ${complexityLevel} learner.

            Structure:
            1. **The Hook**: Why this matters right now.
            2. **Core Concept**: The main lesson.
            3. **3 Actionable Steps**: Practical things the user can do immediately.
            4. **Pro Tip**: A secret or advanced insight.

            Format: Markdown (use headers, bolding, lists).
            Tone: Encouraging, professional, expert coach.
            Length: ~400 words.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
            });
            content.text = response.text || "Content generation failed.";
        } 
        else if (resource.type === 'podcast') {
            const prompt = `
            Create a lively podcast script for 2 hosts (Alex and Sam) discussing "${resource.title}".
            Focus: ${resource.category}.
            Target Audience: ${complexityLevel}.

            Format:
            - Start with a quick energetic intro.
            - Alex explains the problem/topic.
            - Sam provides a solution or a "hack".
            - They roleplay a tiny 10-second example of doing it right vs wrong.
            - Quick summary and sign-off.

            Tone: Fun, fast-paced, like a radio show.
            Length: Approx 2 minutes spoken.
            Output: Just the dialogue text.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-preview-tts',
                contents: [{ parts: [{ text: prompt }] }],
                config: {
                    responseModalities: [Modality.AUDIO],
                    speechConfig: {
                        multiSpeakerVoiceConfig: {
                            speakerVoiceConfigs: [
                                { speaker: 'Alex', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } } },
                                { speaker: 'Sam', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Aoede' } } }
                            ]
                        }
                    }
                }
            });

            const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (audioData) {
                const wavBlob = pcmToWav(decode(audioData));
                content.audioUrl = URL.createObjectURL(wavBlob);
            }
        }
        else if (resource.type === 'video') {
            // Video Simulation: 1. Audio (Narration) 2. Visual (Thumbnail)

            // 1. Script & Audio
            const scriptPrompt = `
            You are recording a video lesson for "${resource.title}".
            Write the narration script.
            Target Audience: ${complexityLevel}.

            Structure:
            - "Hey everyone, welcome back to FluentFlow."
            - Define the specific problem regarding ${resource.category}.
            - Give one concrete exercise to fix it.
            - "Try this today and let me know how it goes."

            Tone: Youtube Educator (Warm, clear, concise).
            Length: 60 seconds spoken.
            `;

            const audioResponse = await ai.models.generateContent({
                model: 'gemini-2.5-flash-preview-tts',
                contents: [{ parts: [{ text: scriptPrompt }] }],
                config: {
                    responseModalities: [Modality.AUDIO],
                    speechConfig: {
                         voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } // Deep authoritative voice
                    }
                }
            });

            const audioData = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (audioData) {
                const wavBlob = pcmToWav(decode(audioData));
                content.audioUrl = URL.createObjectURL(wavBlob);
            }

            // 2. Thumbnail
            const imagePrompt = `
            A modern, flat vector illustration for a video thumbnail about "${resource.title}".
            Style: Corporate Memphis, minimal, vibrant colors (Blue, Orange, White).
            Subject: Abstract representation of ${resource.category}, communication, speaking, or confidence.
            Text free. High quality.
            `;

            try {
                const imageResponse = await ai.models.generateContent({
                    model: 'gemini-2.5-flash-image',
                    contents: { parts: [{ text: imagePrompt }] },
                });

                // Iterate parts to find image data as per guidelines
                const parts = imageResponse.candidates?.[0]?.content?.parts;
                let imageData;
                if (parts) {
                    for (const part of parts) {
                        if (part.inlineData) {
                            imageData = part.inlineData.data;
                            break;
                        }
                    }
                }

                if (imageData) {
                     content.imageUrl = `data:image/jpeg;base64,${imageData}`;
                }
            } catch (imgErr) {
                console.warn("Image gen failed", imgErr);
            }
        }
    } catch (e) {
        console.error("Content generation failed", e);
        throw e;
    }

    return content;
};

import React, { useState, useEffect, useRef } from 'react';
import { SCENARIOS, DEFAULT_USER_STATS, DEFAULT_AVATAR_CONFIG, LEVEL_THRESHOLDS, getLanguageSystemInstruction, AVATAR_OPTIONS, DEFAULT_SESSION_SETTINGS, RESOURCES as FALLBACK_RESOURCES } from './constants';
import { Scenario, UserStats, AvatarConfig, LanguageConfig, User, Friend, SessionReport, SessionSettings, SessionHistoryItem, Resource } from './types';
import ScenarioCard from './components/ScenarioCard';
import ActiveSession from './components/ActiveSession';
import AvatarEditor from './components/AvatarEditor';
import Avatar from './components/Avatar';
import AuthScreen from './components/AuthScreen';
import FriendsPanel from './components/FriendsPanel';
import SessionSummary from './components/SessionSummary';
import ScenarioBuilder from './components/ScenarioBuilder';
import SessionSetup from './components/SessionSetup';
import SessionHistoryList from './components/SessionHistoryList';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import { fetchDailyRecommendations, generateResourceContent } from './services/resourceGenerator';
import ReactMarkdown from 'react-markdown'; 

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);

  // Navigation State
  const [activeScenario, setActiveScenario] = useState<Scenario | null>(null);
  const [pendingScenario, setPendingScenario] = useState<Scenario | null>(null); 

  const [isEditingAvatar, setIsEditingAvatar] = useState(false);
  const [isBuildingScenario, setIsBuildingScenario] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showAnalytics, setShowAnalytics] = useState(false);
  const [activeResource, setActiveResource] = useState<Resource | null>(null);
  const [viewingHistoryItem, setViewingHistoryItem] = useState<SessionHistoryItem | null>(null);

  const [customScenarios, setCustomScenarios] = useState<Scenario[]>([]);

  // Persist state in local storage simulation
  const [userStats, setUserStats] = useState<UserStats>(DEFAULT_USER_STATS);
  const [avatarConfig, setAvatarConfig] = useState<AvatarConfig>(DEFAULT_AVATAR_CONFIG);
  const [lastSessionReport, setLastSessionReport] = useState<SessionReport | null>(null);
  const [earnedXP, setEarnedXP] = useState(0);

  const [currentSessionSettings, setCurrentSessionSettings] = useState<SessionSettings>(DEFAULT_SESSION_SETTINGS);
  const [initialTranscript, setInitialTranscript] = useState<any[] | undefined>(undefined);

  // Resource State
  const [dailyResources, setDailyResources] = useState<Resource[]>([]);
  const [isLoadingResources, setIsLoadingResources] = useState(false);
  const [isGeneratingContent, setIsGeneratingContent] = useState(false);

  useEffect(() => {
    // Check for existing session
    const savedUser = localStorage.getItem('fluentflow_user');
    const savedAvatar = localStorage.getItem('fluentflow_avatar');
    const savedScenarios = localStorage.getItem('fluentflow_custom_scenarios');

    if (savedUser) {
        try {
            const parsedUser = JSON.parse(savedUser);
            setUser(parsedUser);
            if (parsedUser.stats) {
                setUserStats(parsedUser.stats);
            }
        } catch (e) {
            console.error("Failed to parse user", e);
        }
    }
    if (savedAvatar) setAvatarConfig(JSON.parse(savedAvatar));
    if (savedScenarios) setCustomScenarios(JSON.parse(savedScenarios));
  }, []);

  // Daily Resource Logic
  useEffect(() => {
    if (!user) return;

    const today = new Date().toDateString();
    const cacheKey = `fluentflow_resources_${user.id}_${today}`;
    const cached = localStorage.getItem(cacheKey);

    if (cached) {
        setDailyResources(JSON.parse(cached));
    } else {
        // Generate new resources
        const initResources = async () => {
            setIsLoadingResources(true);
            try {
                const newResources = await fetchDailyRecommendations(userStats, user.history || [], process.env.API_KEY || '');
                if (newResources.length > 0) {
                    setDailyResources(newResources);
                    localStorage.setItem(cacheKey, JSON.stringify(newResources));
                } else {
                    setDailyResources(FALLBACK_RESOURCES);
                }
            } catch (e) {
                console.error("Failed to fetch resources", e);
                setDailyResources(FALLBACK_RESOURCES);
            } finally {
                setIsLoadingResources(false);
            }
        };
        initResources();
    }
  }, [user?.id, userStats.level]); // Re-run if user changes

  useEffect(() => {
    if (user) {
        const updatedUser = { ...user, stats: userStats };
        localStorage.setItem('fluentflow_user', JSON.stringify(updatedUser));

        try {
            const dbStr = localStorage.getItem('fluentflow_users_db');
            if (dbStr) {
                const db = JSON.parse(dbStr);
                const userIndex = db.findIndex((u: any) => u.id === user.id);
                if (userIndex >= 0) {
                    db[userIndex] = { ...db[userIndex], ...updatedUser };
                    localStorage.setItem('fluentflow_users_db', JSON.stringify(db));
                }
            }
        } catch (e) {
            console.error("Failed to sync user to DB", e);
        }
    }
  }, [user, userStats]);

  useEffect(() => {
    localStorage.setItem('fluentflow_avatar', JSON.stringify(avatarConfig));
  }, [avatarConfig]);

  useEffect(() => {
    localStorage.setItem('fluentflow_custom_scenarios', JSON.stringify(customScenarios));
  }, [customScenarios]);

  // Calculate Level Progress
  const currentLevelBaseXP = LEVEL_THRESHOLDS[userStats.level - 1] || 0;
  const nextLevelXP = LEVEL_THRESHOLDS[userStats.level] || 10000;
  const progressPercent = Math.min(100, Math.max(0, ((userStats.xp - currentLevelBaseXP) / (nextLevelXP - currentLevelBaseXP)) * 100));

  const handleAuthComplete = (newUser: User) => {
    setUser(newUser);
    if (newUser.stats) {
        setUserStats(newUser.stats);
    } else {
        setUserStats(DEFAULT_USER_STATS);
    }
  };

  const handleAddFriend = (name: string) => {
    if (!user) return;

    const randomSkin = AVATAR_OPTIONS.skinColors[Math.floor(Math.random() * AVATAR_OPTIONS.skinColors.length)];
    const randomHair = AVATAR_OPTIONS.hairColors[Math.floor(Math.random() * AVATAR_OPTIONS.hairColors.length)];
    const level = Math.floor(Math.random() * 5) + 1;

    const newFriend: Friend = {
        id: Date.now().toString(),
        name: name,
        level: level,
        xp: level * 500, 
        isOnline: Math.random() > 0.5,
        lastActive: 'Today',
        avatarConfig: {
            ...DEFAULT_AVATAR_CONFIG,
            skinColor: randomSkin,
            hairColor: randomHair
        }
    };

    const updatedUser = {
        ...user,
        friends: [...user.friends, newFriend]
    };
    setUser(updatedUser);
  };

  const handleScenarioClick = (scenario: Scenario) => {
      setPendingScenario(scenario);
  };

  const handleStartSession = (settings: SessionSettings) => {
      if (pendingScenario) {
          setCurrentSessionSettings(settings);
          setInitialTranscript(undefined); 
          setActiveScenario(pendingScenario);
          setPendingScenario(null);
      }
  };

  const handleQuickStart = () => {
    const debateScenario = SCENARIOS.find(s => s.id === 'debate');
    if (debateScenario) {
        setCurrentSessionSettings({
            ...DEFAULT_SESSION_SETTINGS,
            difficulty: 'beginner',
            language: 'English'
        });
        setInitialTranscript(undefined);
        setActiveScenario(debateScenario);
    }
  };

  const handleResumeSession = (historyItem: SessionHistoryItem) => {
      let scenario = [...SCENARIOS, ...customScenarios].find(s => s.id === historyItem.scenarioId);

      if (!scenario && historyItem.scenarioId.startsWith('language_')) {
         const langId = historyItem.scenarioId.split('_')[1];
         // Fallback logic for old language sessions
         scenario = {
             id: historyItem.scenarioId,
             title: historyItem.scenarioTitle,
             description: 'Resumed Language Session',
             icon: 'fa-language',
             color: 'bg-indigo-600',
             voiceName: 'Puck',
             systemInstruction: getLanguageSystemInstruction(historyItem.scenarioTitle.replace(' Tutor', ''))
         }
      }

      if (scenario) {
          setCurrentSessionSettings(historyItem.settings);
          setInitialTranscript(historyItem.report.transcript);
          setActiveScenario(scenario);
          setShowHistory(false);
      }
  };

  const handleViewHistoryDetails = (item: SessionHistoryItem) => {
    setViewingHistoryItem(item);
  };

  const handleSaveCustomScenario = (scenario: Scenario) => {
    setCustomScenarios(prev => [...prev, scenario]);
    setIsBuildingScenario(false);
  };

  const handleDeleteCustomScenario = (id: string) => {
    if (window.confirm("Are you sure you want to delete this custom scenario?")) {
        setCustomScenarios(prev => prev.filter(s => s.id !== id));
    }
  };

  const handleSessionEnd = (report: SessionReport, isSaved: boolean = false) => {
    const endedScenario = activeScenario!;
    const settingsUsed = currentSessionSettings;

    setActiveScenario(null);
    setInitialTranscript(undefined);

    // Only award XP if completed
    let xp = 0;
    if (!isSaved) {
        xp = Math.floor((report.durationSeconds / 60) * 10) + 50;
        if (report.dominantEmotion === 'Confident' || report.dominantEmotion === 'Excited') {
            xp += 20; 
        }
        setEarnedXP(xp);
        setLastSessionReport(report); // Shows modal
    }

    if (!user) return;

    const historyItem: SessionHistoryItem = {
        id: Date.now().toString(),
        scenarioId: endedScenario.id,
        scenarioTitle: endedScenario.title,
        date: new Date().toISOString(),
        durationSeconds: report.durationSeconds,
        settings: settingsUsed,
        report: report,
        status: isSaved ? 'saved' : 'completed'
    };

    const newHistory = [historyItem, ...(user.history || [])];

    const today = new Date().toDateString();
    const lastDate = userStats.lastSessionDate ? new Date(userStats.lastSessionDate).toDateString() : null;
    let newStreak = userStats.streak;

    // Update streak only if session completed
    if (!isSaved && lastDate !== today) {
        if (lastDate) {
            const diffTime = Math.abs(new Date(today).getTime() - new Date(lastDate).getTime());
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 
            if (diffDays === 1) newStreak++;
            else if (diffDays > 1) newStreak = 1;
        } else {
            newStreak = 1;
        }
    }

    updateXP(xp, newStreak, newHistory);
  };

  const updateXP = (amount: number, newStreak?: number, newHistory?: SessionHistoryItem[]) => {
      const newTotalXP = userStats.xp + amount;
      let newLevel = userStats.level;
      while (newLevel < LEVEL_THRESHOLDS.length && newTotalXP >= LEVEL_THRESHOLDS[newLevel]) {
          newLevel++;
      }

      setUserStats(prev => ({
          ...prev,
          xp: newTotalXP,
          level: newLevel,
          streak: newStreak !== undefined ? newStreak : prev.streak,
          sessionsCompleted: newHistory ? prev.sessionsCompleted + 1 : prev.sessionsCompleted,
          lastSessionDate: newHistory ? new Date().toISOString() : prev.lastSessionDate
      }));

      if (newHistory && user) {
          setUser({ ...user, history: newHistory });
      }
  };

  const handleResourceClick = async (resource: Resource) => {
      setActiveResource(resource);

      // If content not generated yet, generate it
      if (!resource.content) {
          setIsGeneratingContent(true);
          try {
              const content = await generateResourceContent(resource, process.env.API_KEY || '');

              // Update local state and storage with generated content to cache it
              const updatedResource = { ...resource, content };
              setActiveResource(updatedResource);

              const updatedDaily = dailyResources.map(r => r.id === resource.id ? updatedResource : r);
              setDailyResources(updatedDaily);

              // Update cache
              const today = new Date().toDateString();
              const cacheKey = `fluentflow_resources_${user!.id}_${today}`;
              localStorage.setItem(cacheKey, JSON.stringify(updatedDaily));

          } catch (e) {
              console.error("Content generation failed", e);
              // alert("Failed to generate content. Please try again.");
          } finally {
              setIsGeneratingContent(false);
          }
      }
  };

  const handleResourceComplete = () => {
     if (!activeResource) return;
     updateXP(activeResource.xp);
     setActiveResource(null);
  };

  const resetViews = () => {
    setActiveScenario(null);
    setPendingScenario(null);
    setIsEditingAvatar(false);
    setIsBuildingScenario(false);
    setShowHistory(false);
    setShowAnalytics(false);
    setActiveResource(null);
    setViewingHistoryItem(null);
  };

  const handleLogout = () => {
      localStorage.removeItem('fluentflow_user');
      localStorage.removeItem('fluentflow_avatar');
      setUser(null);
      setUserStats(DEFAULT_USER_STATS); 
