      if (isInputActive || isSpeaking) {
        lastActiveTimeRef.current = now;
        return;
      }
      if (now - lastActiveTimeRef.current > PAUSE_THRESHOLD) {
        if (!coachingTip || coachingTip.type !== 'hesitation') {
            triggerTip(FLUENCY_TIPS.pauses[Math.floor(Math.random() * FLUENCY_TIPS.pauses.length)], 'hesitation', 8000);
            setAwkwardPauseCount(p => p + 1);
            setHesitationScore(h => h + 5);
            lastActiveTimeRef.current = now; 
        }
      }
    };
    const interval = setInterval(checkActivity, 200);
    return () => clearInterval(interval);
  }, [status, isSpeaking, coachingTip, triggerTip]);

