                    <i className="fa-solid fa-circle-notch animate-spin"></i>
                ) : (
                    <i className="fa-solid fa-download"></i>
                )}
                <span className="hidden sm:inline">Export Audio</span>
            </button>
            <button 
                onClick={() => onEndSession({ durationSeconds: (Date.now() - startTime)/1000, fillerWordCount: fillerCount, awkwardPauseCount, fillerWordsPerMinute: fillerCount/((Date.now()-startTime)/60000), transcript: transcripts, dominantEmotion: currentEmotion }, true, clientRef.current?.getSessionRecording() || undefined)} 
                className="bg-white text-slate-600 px-3 py-2 rounded-lg text-xs font-bold hover:bg-slate-50 border border-slate-200 transition-colors"
            >
                Save
            </button>
            <button 
                onClick={() => { setIsAnalyzing(true); onEndSession({ durationSeconds: (Date.now() - startTime)/1000, fillerWordCount: fillerCount, awkwardPauseCount, fillerWordsPerMinute: fillerCount/((Date.now()-startTime)/60000), transcript: transcripts, dominantEmotion: currentEmotion }, false, clientRef.current?.getSessionRecording() || undefined); }} 
                className="bg-red-50 text-red-600 px-4 py-2 rounded-lg text-xs font-bold hover:bg-red-100 transition-colors"
            >
                Finish Session
            </button>
        </div>
      </div>

      {/* Main View */}
      <div className="flex-1 relative flex flex-col min-h-0 bg-slate-50/30">
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className="w-64 h-64 md:w-80 md:h-80 relative flex flex-col items-center justify-center">
                {/* Meta Badges */}
                <div className="absolute -top-8 w-full flex justify-center gap-2 animate-fade-in-up z-30">
                    <div className="bg-white/90 backdrop-blur px-2 py-0.5 rounded-full border border-slate-200 text-[10px] font-bold shadow-sm flex items-center gap-1 transition-all">
                        <i className="fa-solid fa-face-smile text-brand-500"></i> {currentEmotion}
                    </div>
                    <div className="bg-white/90 backdrop-blur px-2 py-0.5 rounded-full border border-slate-200 text-[10px] font-bold shadow-sm flex items-center gap-1 transition-all">
                        <i className="fa-solid fa-bullseye text-blue-500"></i> {currentIntent}
                    </div>
                </div>
                {isSpeaking && (
                    <>
                        <div className="absolute inset-0 bg-brand-200 rounded-full animate-ping opacity-10"></div>
                        <div className="absolute -inset-4 border-2 border-brand-100 rounded-full animate-pulse opacity-20"></div>
                    </>
                )}
                <LiveAvatar config={avatarConfig} volumeRef={volumeRef} isSpeaking={isSpeaking} />
            </div>
         </div>

         <div 
            ref={scrollRef} 
            onScroll={handleScroll}
            className="relative z-10 flex-1 overflow-y-auto p-6 space-y-4"
            style={{ maskImage: 'linear-gradient(to bottom, transparent 0%, black 15%)' }}
         >
            {transcripts.map((t, idx) => (
                <div key={idx} className={`flex ${t.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                    <div className={`max-w-[80%] rounded-2xl px-5 py-3 text-sm leading-relaxed shadow-sm ${t.role === 'user' ? 'bg-slate-900 text-white rounded-br-none' : 'bg-white border border-slate-200 text-slate-800 rounded-bl-none'}`}>
                        {getCleanText(t.text)}
                    </div>
                </div>
            ))}
            <div className="h-4"></div>
         </div>

         {/* Subtle Footer Tooltip Area */}
         <div className="h-24 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col items-center justify-center shrink-0">
            <LiveVisualizer volumeRef={volumeRef} isActive={status === ConnectionStatus.CONNECTED} patienceProgress={patienceProgress} />
            <div className="h-8 flex items-center justify-center w-full">
                {coachingTip ? (
                    <div className="animate-fade-in-up flex items-center gap-2 px-4 py-1.5 rounded-full bg-brand-50 border border-brand-100 shadow-sm transition-all hover:scale-105">
                        <i className={`fa-solid text-brand-600 text-[10px] ${coachingTip.type === 'hesitation' ? 'fa-hourglass' : 'fa-lightbulb'}`}></i>
                        <span className="text-xs font-bold text-slate-700">{coachingTip.text}</span>
                    </div>
                ) : (
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest animate-fade-in">
                        {status === ConnectionStatus.CONNECTED ? (patienceProgress > 0.5 ? 'AI is waiting for you to finish...' : 'Listening...') : 'Initializing AI Coach...'}
                    </p>
                )}
            </div>
         </div>
      </div>
    </div>
  );
};

export default ActiveSession;

export interface EmailValidationResult {
  isValid: boolean;
  error?: string;
  suggestion?: string;
  isDisposable?: boolean;
  domainReputation?: 'high' | 'medium' | 'low' | 'suspicious';
}

const COMMON_DOMAINS = ['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'icloud.com', 'live.com', 'me.com', 'protonmail.com', 'icloud.com'];

const DISPOSABLE_DOMAINS = [
  'mailinator.com', '10minutemail.com', 'tempmail.com', 'guerrillamail.com', 'trashmail.com',
  'yopmail.com', 'dispostable.com', 'sharklasers.com', 'getnada.com', 'owlymail.com',
  'evonax.com', 'is-not-a.net', 'temp-mail.org', 'fake-mail.com'
];

/**
 * Validates basic email format and checks for common typos
 */
export const validateEmailFormat = (email: string): EmailValidationResult => {
  const cleanEmail = email.trim().toLowerCase();

  if (!cleanEmail) {
    return { isValid: false, error: 'Email is required.' };
  }

  // RFC-compliant-ish Regex
  const regex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  if (!regex.test(cleanEmail)) {
    return { isValid: false, error: 'Please enter a valid email format.' };
  }

  const [localPart, domain] = cleanEmail.split('@');

  // Typo Suggestion
  const typos: Record<string, string> = {
    'gmial.com': 'gmail.com',
    'gmal.com': 'gmail.com',
    'gmaill.com': 'gmail.com',
    'yaho.com': 'yahoo.com',
    'hotmial.com': 'hotmail.com',
    'outlok.com': 'outlook.com',
    'proton.com': 'protonmail.com'
  };

  if (typos[domain]) {
    return { 
      isValid: true, 
      suggestion: `${localPart}@${typos[domain]}` 
    };
  }

  return { isValid: true };
};

/**
 * Asynchronously verifies if a domain is reputable and likely to accept mail
 * In a real app, this would be an API call to a service like Hunter.io or ZeroBounce
 */
export const verifyDomainReputation = async (email: string): Promise<EmailValidationResult> => {
  const formatCheck = validateEmailFormat(email);
  if (!formatCheck.isValid) return formatCheck;

  const domain = email.split('@')[1].toLowerCase();

  // Simulate network latency for "verification"
  await new Promise(resolve => setTimeout(resolve, 600));

  if (DISPOSABLE_DOMAINS.includes(domain)) {
    return {
      isValid: false,
      error: `The domain "${domain}" is a known disposable email provider. Please use a permanent address.`,
      isDisposable: true,
      domainReputation: 'suspicious'
    };
  }

  // Basic "Real" Domain check simulation
  const isCommon = COMMON_DOMAINS.includes(domain);
  const isLikelyEducational = domain.endsWith('.edu');
  const isLikelyGovernment = domain.endsWith('.gov');

  if (!isCommon && !isLikelyEducational && !isLikelyGovernment) {
      // Logic for "unrecognized" but potentially valid business domains
      return { 
          isValid: true, 
          domainReputation: 'medium' 
      };
  }

  return { 
      isValid: true, 
      domainReputation: 'high' 
  };
};

/**
 * Checks if email already exists in the simulated database
 */
export const checkAccountExists = (email: string): boolean => {
    const usersDbStr = localStorage.getItem('fluentflow_users_db');
    if (!usersDbStr) return false;
    const usersDb = JSON.parse(usersDbStr);
    return usersDb.some((u: any) => u.email.toLowerCase() === email.trim().toLowerCase());
};

import React, { useState, useEffect, useRef } from 'react';
import { User } from '../types';
import { DEFAULT_USER_STATS } from '../constants';
import { validateEmailFormat, verifyDomainReputation, checkAccountExists, EmailValidationResult } from '../services/validation';

interface AuthScreenProps {
  onComplete: (user: User) => void;
}

type AuthView = 'login' | 'signup' | 'forgot-password' | 'reset-password';

const AuthScreen: React.FC<AuthScreenProps> = ({ onComplete }) => {
  const [view, setView] = useState<AuthView>('signup');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [recoveryCode, setRecoveryCode] = useState('');

  const [emailValidation, setEmailValidation] = useState<EmailValidationResult>({ isValid: false });
  const [isVerifyingEmail, setIsVerifyingEmail] = useState(false);
  const [accountAlreadyExists, setAccountAlreadyExists] = useState(false);
  const [showValidationUI, setShowValidationUI] = useState(false);

  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  // Debounced real-time validation
  const validationTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    if (validationTimeoutRef.current) clearTimeout(validationTimeoutRef.current);

    if (email.length > 5) {
      setIsVerifyingEmail(true);
      setAccountAlreadyExists(false);

      validationTimeoutRef.current = window.setTimeout(async () => {
        const result = await verifyDomainReputation(email);
        setEmailValidation(result);

        // If domain is valid, check if account exists (only for signup)
        if (result.isValid && view === 'signup') {
            const exists = checkAccountExists(email);
            setAccountAlreadyExists(exists);
        }

        setIsVerifyingEmail(false);
        setShowValidationUI(true);
      }, 500);
    } else {
      setIsVerifyingEmail(false);
      setEmailValidation({ isValid: false });
      setAccountAlreadyExists(false);
      setShowValidationUI(false);
    }

    return () => {
      if (validationTimeoutRef.current) clearTimeout(validationTimeoutRef.current);
    };
  }, [email, view]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMsg(null);

    // Final check
    if (!emailValidation.isValid) {
      setError(emailValidation.error || 'Please provide a valid email.');
      return;
    }

    if (view === 'signup' && accountAlreadyExists) {
        setError('An account with this email already exists.');
        return;
    }

    setIsLoading(true);
    await new Promise(resolve => setTimeout(resolve, 800));

    try {
      const usersDbStr = localStorage.getItem('fluentflow_users_db');
      const usersDb = usersDbStr ? JSON.parse(usersDbStr) : [];

      const cleanEmail = email.trim().toLowerCase();
      const cleanPassword = password.trim();

      if (view === 'signup') {
        if (!name.trim()) throw new Error("Full Name is required.");
        if (!cleanPassword) throw new Error("Password is required.");
        if (cleanPassword.length < 6) throw new Error("Password must be at least 6 characters long.");
        if (cleanPassword !== confirmPassword) throw new Error("Passwords do not match.");

        const newUser: User = {
          id: Date.now().toString(),
          name: name.trim(),
          email: cleanEmail,
          friends: [],
          stats: DEFAULT_USER_STATS,
          history: []
        };

        const dbEntry = { ...newUser, password: cleanPassword }; 
        usersDb.push(dbEntry);
        localStorage.setItem('fluentflow_users_db', JSON.stringify(usersDb));

        onComplete(newUser);
      } 
      else if (view === 'login') {
        if (!cleanPassword) throw new Error("Password is required.");

        const userIndex = usersDb.findIndex((u: any) => 
            u.email.toLowerCase() === cleanEmail && 
            u.password === cleanPassword
        );

        if (userIndex === -1) {
          const emailExists = usersDb.some((u: any) => u.email.toLowerCase() === cleanEmail);
          throw new Error(emailExists ? "Incorrect password." : "No account found with this email.");
        }

        const user = usersDb[userIndex];
        const { password: _, ...safeUser } = user;
        onComplete(safeUser as User);
      }
      else if (view === 'forgot-password') {
          const userExists = usersDb.some((u: any) => u.email.toLowerCase() === cleanEmail);
          if (!userExists) throw new Error("No account found with this email.");
          setSuccessMsg(`Recovery code sent to ${cleanEmail}`);
          setView('reset-password');
      }
      else if (view === 'reset-password') {
          if (!recoveryCode.trim()) throw new Error("Recovery code is required.");
          if (!newPassword.trim()) throw new Error("New password is required.");
          const userIndex = usersDb.findIndex((u: any) => u.email.toLowerCase() === cleanEmail);
          if (userIndex === -1) throw new Error("User not found."); 
          usersDb[userIndex].password = newPassword.trim();
          localStorage.setItem('fluentflow_users_db', JSON.stringify(usersDb));
          setSuccessMsg("Password reset successfully.");
          setTimeout(() => setView('login'), 1500);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleView = (newView: AuthView) => {
    setView(newView);
    setError(null);
    setSuccessMsg(null);
    setPassword('');
    setEmail('');
    setShowValidationUI(false);
  };

  const applySuggestion = () => {
    if (emailValidation.suggestion) {
      setEmail(emailValidation.suggestion);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">
        <div className="bg-brand-600 p-8 text-center">
            <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg text-brand-600 text-2xl">
                <i className="fa-solid fa-wave-square"></i>
            </div>
            <h1 className="text-3xl font-bold text-white mb-1">FluentFlow</h1>
            <p className="text-brand-100 opacity-90">AI-Powered Confidence Coach</p>
        </div>

        <div className="p-8">
            <h2 className="text-xl font-bold text-slate-900 mb-6 text-center">
                {view === 'login' && 'Welcome Back'}
                {view === 'signup' && 'Create Your Account'}
                {view === 'forgot-password' && 'Recover Password'}
                {view === 'reset-password' && 'Set New Password'}
            </h2>

            {error && (
                <div className="mb-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg flex items-center gap-2 border border-red-100 animate-fade-in">
                    <i className="fa-solid fa-circle-exclamation shrink-0"></i>
                    <span>{error}</span>
                </div>
            )}

            {successMsg && (
                <div className="mb-4 p-3 bg-green-50 text-green-600 text-sm rounded-lg flex items-center gap-2 border border-green-100 animate-fade-in">
                    <i className="fa-solid fa-check-circle shrink-0"></i>
                    <span>{successMsg}</span>
                </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4">
                {view === 'signup' && (
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Full Name</label>
                        <input 
                            type="text" 
                            name="name"
                            autoComplete="name"
                            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-brand-500 focus:ring-2 focus:ring-brand-200 outline-none transition-all bg-white text-slate-900 placeholder-slate-400"
                            placeholder="John Doe"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                        />
                    </div>
                )}

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email Address</label>
                    <div className="relative">
                        <input 
                            type="email" 
                            name="email"
                            autoComplete="email"
                            className={`w-full px-4 py-3 rounded-xl border outline-none transition-all bg-white text-slate-900 placeholder-slate-400 pr-10 ${
                                isVerifyingEmail 
                                ? 'border-brand-300 ring-2 ring-brand-100'
                                : showValidationUI && (!emailValidation.isValid || accountAlreadyExists)
                                    ? 'border-red-300 bg-red-50/30' 
                                    : email.length > 5 && emailValidation.isValid 
                                        ? 'border-green-300 bg-green-50/30' 
                                        : 'border-slate-200 focus:border-brand-500 focus:ring-2 focus:ring-brand-200'
                            }`}
                            placeholder="you@example.com"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            disabled={view === 'reset-password'}
                        />
                        <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-2">
                            {isVerifyingEmail ? (
                                <i className="fa-solid fa-circle-notch animate-spin text-brand-500"></i>
                            ) : (
                                <>
                                    {email.length > 5 && showValidationUI && (
                                        (emailValidation.isValid && !accountAlreadyExists)
                                        ? <i className="fa-solid fa-circle-check text-green-500"></i>
                                        : <i className="fa-solid fa-circle-xmark text-red-400"></i>
                                    )}
                                </>
                            )}
                        </div>
                    </div>

                    {/* TYPO SUGGESTION */}
                    {emailValidation.suggestion && (
                        <button 
                            type="button"
                            onClick={applySuggestion}
                            className="mt-1 text-[11px] text-brand-600 font-bold hover:text-brand-800 transition-colors flex items-center gap-1"
                        >
                            <i className="fa-solid fa-wand-magic-sparkles"></i>
                            Did you mean {emailValidation.suggestion}?
                        </button>
                    )}

                    {/* DOMAIN/ACCOUNT WARNINGS */}
                    {showValidationUI && !isVerifyingEmail && (
                        <>
                            {accountAlreadyExists && view === 'signup' && (
                                <p className="mt-1 text-[11px] text-red-500 font-bold flex items-center gap-1">
                                    <i className="fa-solid fa-user-xmark"></i> This account already exists.
                                </p>
                            )}
                            {!emailValidation.isValid && emailValidation.error && (
                                <p className="mt-1 text-[11px] text-red-500 font-medium">
                                    {emailValidation.error}
                                </p>
                            )}
                            {emailValidation.isValid && emailValidation.domainReputation === 'medium' && (
                                <p className="mt-1 text-[10px] text-slate-400 font-medium">
                                    Using an unrecognized domain. Verification might be slower.
                                </p>
                            )}
                        </>
                    )}
                </div>

                {(view === 'login' || view === 'signup') && (
                    <div>
                        <div className="flex justify-between items-center mb-1">
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Password</label>
                            {view === 'login' && (
                                <button type="button" onClick={() => toggleView('forgot-password')} className="text-xs text-brand-600 hover:text-brand-800 font-medium">Forgot?</button>
                            )}
                        </div>
                        <div className="relative">
                            <input 
                                type={showPassword ? "text" : "password"} 
                                name="password"
                                autoComplete={view === 'signup' ? "new-password" : "current-password"}
                                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-brand-500 focus:ring-2 focus:ring-brand-200 outline-none transition-all bg-white text-slate-900 placeholder-slate-400 pr-10"
                                placeholder="••••••••"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 p-2"
                            >
                                <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
                            </button>
                        </div>
                    </div>
                )}

                {view === 'signup' && (
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Confirm Password</label>
                        <div className="relative">
                            <input 
                                type={showConfirmPassword ? "text" : "password"} 
                                name="confirmPassword"
                                autoComplete="new-password"
                                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-brand-500 focus:ring-2 focus:ring-brand-200 outline-none transition-all bg-white text-slate-900 placeholder-slate-400 pr-10"
                                placeholder="••••••••"
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                            />
                            <button
                                type="button"
                                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 p-2"
                            >
                                <i className={`fa-solid ${showConfirmPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
                            </button>
                        </div>
                    </div>
                )}

                <button 
                    type="submit" 
                    disabled={isLoading || isVerifyingEmail || (view === 'signup' && (!emailValidation.isValid || accountAlreadyExists))}
                    className={`w-full py-4 rounded-xl text-white font-bold text-lg shadow-lg shadow-brand-200 transition-all transform active:scale-95 flex items-center justify-center gap-2 ${isLoading ? 'bg-brand-400 cursor-wait' : 'bg-brand-600 hover:bg-brand-700 hover:-translate-y-1 disabled:opacity-50 disabled:translate-y-0 disabled:shadow-none'}`}
                >
                    {isLoading ? (
                        <><i className="fa-solid fa-circle-notch animate-spin"></i> Processing...</>
                    ) : (
                        <>
                            {view === 'login' && 'Sign In'}
                            {view === 'signup' && 'Create Account'}
                            {view === 'forgot-password' && 'Send Recovery Code'}
                            {view === 'reset-password' && 'Reset Password'}
                        </>
                    )}
                </button>
            </form>

            <div className="mt-6 text-center">
                {view === 'login' ? (
                    <p className="text-slate-500 text-sm">
                        Don't have an account?{' '}
                        <button onClick={() => toggleView('signup')} className="text-brand-600 font-bold hover:underline">Sign Up</button>
                    </p>
                ) : view === 'signup' ? (
                    <p className="text-slate-500 text-sm">
                        Already have an account?{' '}
                        <button onClick={() => toggleView('login')} className="text-brand-600 font-bold hover:underline">Log In</button>
                    </p>
                ) : (
                    <button onClick={() => toggleView('login')} className="text-slate-500 text-sm hover:text-brand-600 font-medium flex items-center gap-1 justify-center mx-auto">
                        <i className="fa-solid fa-arrow-left"></i> Back to Login
                    </button>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

