import { GoogleGenAI, Type, Modality } from "@google/genai";
import { pcmToWav, decode } from "./audioUtils";

export interface MultiCoachResponse {
  coach1: string;
  coach2: string;
  coach3: string;
  audioUrl?: string;
}

export const processMultiCoachTurn = async (
  userInput: string,
  history: { role: string; text: string }[],
  apiKey: string,
  onProgress: (coach: 1 | 2 | 3) => void
): Promise<MultiCoachResponse> => {
  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-pro-preview';

  // 1. Coach 1: Fluency Expert
  onProgress(1);
  const c1Response = await ai.models.generateContent({
    model,
    contents: `Fluency Expert. Analyze ONLY the user's latest input: "${userInput}". 
    Focus on fillers, pauses, and pace. Speak directly to the user. Keep it under 40 words.`,
    config: {
      systemInstruction: "You are Coach 1, a Fluency Expert. You provide immediate, sharp feedback on speech flow."
    }
  });
  const coach1Text = c1Response.text || "I noticed some hesitation in your delivery.";

  // 2. Coach 2: Confidence Coach
  onProgress(2);
  const c2Response = await ai.models.generateContent({
    model,
    contents: `Confidence Coach. Build on the session so far. 
    User said: "${userInput}". 
    Coach 1 said: "${coach1Text}".
    Focus on tone, assertiveness, and body language (perceived). Speak directly to the user. Under 40 words.`,
    config: {
      systemInstruction: "You are Coach 2, a Confidence Coach. You focus on the user's presence and emotional impact."
    }
  });
  const coach2Text = c2Response.text || "Your tone is improving, but try to project more energy.";

  // 3. Coach 3: Synthesis Coach
  onProgress(3);
  const c3Response = await ai.models.generateContent({
    model,
    contents: `Synthesis Coach. Summarize the user's progress and previous coach feedback.
    User: "${userInput}"
    C1: "${coach1Text}"
    C2: "${coach2Text}"
    Provide 3 quick actionable steps. Under 60 words.`,
    config: {
      systemInstruction: "You are Coach 3, the Synthesis Coach. You wrap up turns with high-level advice."
    }
  });
  const coach3Text = c3Response.text || "To wrap up: focus on breathing, expand your vocab, and keep this pace.";

  // 4. Multi-Speaker TTS Generation
  const ttsPrompt = `TTS the following conversation between three coaches:
  Coach1: ${coach1Text}
  Coach2: ${coach2Text}
  Coach3: ${coach3Text}`;

  let audioUrl: string | undefined;
  try {
    const ttsResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: ttsPrompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: 'Coach1', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
              { speaker: 'Coach2', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
              { speaker: 'Coach3', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
            ]
          }
        }
      }
    });

    const base64Audio = ttsResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const wavBlob = pcmToWav(decode(base64Audio), 24000);
      audioUrl = URL.createObjectURL(wavBlob);
    }
  } catch (e) {
    console.warn("Multi-speaker TTS failed", e);
  }

  return {
    coach1: coach1Text,
    coach2: coach2Text,
    coach3: coach3Text,
    audioUrl
  };
};

import React, { useEffect, useRef, useState, useCallback, useMemo, useLayoutEffect } from 'react';
import { Scenario, TranscriptItem, ConnectionStatus, AvatarConfig, SessionReport, SessionSettings, MultiCoachStatus } from '../types';
import { LiveClient } from '../services/liveClient';
import { processMultiCoachTurn } from '../services/multiCoachEngine';
import AudioVisualizer from './AudioVisualizer';
import Avatar from './Avatar';
import { getVoiceMetadata, FILLER_WORDS } from '../constants';

interface ActiveSessionProps {
  scenario: Scenario;
  avatarConfig: AvatarConfig;
  sessionSettings: SessionSettings;
  initialTranscript?: TranscriptItem[];
  onEndSession: (report: SessionReport, isSaved?: boolean, audioBlob?: Blob) => void;
}

const FILLER_WORD_REGEX = new RegExp(`\\b(${FILLER_WORDS.join('|')})\\b`, 'gi');
const TRAILING_CONJUNCTION_REGEX = /\b(and|but|so|because|or|which|that|who)\s*[,]?\s*$/i;
const TERMINAL_PUNCTUATION_REGEX = /[.!?]\s*$/;

const ActiveSession: React.FC<ActiveSessionProps> = ({ scenario, avatarConfig, sessionSettings, initialTranscript, onEndSession }) => {
  const isMultiCoach = (sessionSettings.groupSize || 1) > 1;

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.CONNECTING);
  const [transcripts, setTranscripts] = useState<TranscriptItem[]>(initialTranscript || []);
  const volumeRef = useRef({ input: 0, output: 0 });
  const [startTime] = useState<number>(Date.now());
  const [isSpeaking, setIsSpeaking] = useState(false);

  const [multiCoachStatus, setMultiCoachStatus] = useState<MultiCoachStatus>({
    currentCoach: null,
    isComplete: false
  });

  const [fillerCount, setFillerCount] = useState<number>(0);
  const [awkwardPauseCount, setAwkwardPauseCount] = useState<number>(0);
  const [hesitationScore, setHesitationScore] = useState<number>(0);
  const lastActiveTimeRef = useRef<number>(Date.now());
  const [patienceProgress, setPatienceProgress] = useState(0);

  const clientRef = useRef<LiveClient | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const mountedRef = useRef(true);

  // Sequential Processing Trigger
  const runMultiCoachSequence = useCallback(async (userInput: string) => {
    if (!mountedRef.current) return;
    setStatus(ConnectionStatus.PROCESSING);

    try {
      const result = await processMultiCoachTurn(
        userInput,
        transcripts.map(t => ({ role: t.role, text: t.text })),
        process.env.API_KEY || '',
        (coach) => setMultiCoachStatus(prev => ({ ...prev, currentCoach: coach }))
      );

      setTranscripts(prev => [
        ...prev,
        { id: `c1_${Date.now()}`, role: 'coach1', text: result.coach1, timestamp: Date.now() },
        { id: `c2_${Date.now()}`, role: 'coach2', text: result.coach2, timestamp: Date.now() },
        { id: `c3_${Date.now()}`, role: 'coach3', text: result.coach3, timestamp: Date.now() },
      ]);

      if (result.audioUrl) {
        const audio = new Audio(result.audioUrl);
        audio.onplay = () => setIsSpeaking(true);
        audio.onended = () => setIsSpeaking(false);
        audio.play();
      }

      setMultiCoachStatus({ currentCoach: null, isComplete: true });
      setStatus(ConnectionStatus.CONNECTED);
    } catch (e) {
      console.error("Multi-coach sequence failed", e);
      setStatus(ConnectionStatus.ERROR);
    }
  }, [transcripts]);

  const handleTranscript = useCallback((text: string, isUser: boolean, isFinal: boolean) => {
    if (!mountedRef.current) return;

    if (isUser) {
        lastActiveTimeRef.current = Date.now();
        const matches = text.match(FILLER_WORD_REGEX);
        if (matches) setFillerCount(f => f + matches.length);

        setTranscripts(prev => {
            const last = prev[prev.length - 1];
            if (last && last.role === 'user') {
                return [...prev.slice(0, -1), { ...last, text: last.text + text }];
            }
            return [...prev, { id: Date.now().toString(), role: 'user', text, timestamp: Date.now() }];
        });

        // For Multi-Coach: Trigger chain when user stops
        if (isMultiCoach && isFinal && text.length > 5) {
            runMultiCoachSequence(text);
        }
    } else if (!isMultiCoach) {
        // Only use LiveClient model transcripts in single-coach mode
        setTranscripts(prev => {
            const last = prev[prev.length - 1];
            if (last && last.role === 'model') {
                return [...prev.slice(0, -1), { ...last, text: last.text + text }];
            }
            return [...prev, { id: Date.now().toString(), role: 'model', text, timestamp: Date.now() }];
        });
        setIsSpeaking(true);
        if ((window as any).speakTimeout) clearTimeout((window as any).speakTimeout);
        (window as any).speakTimeout = setTimeout(() => setIsSpeaking(false), 800);
    }
  }, [isMultiCoach, runMultiCoachSequence]);

  useEffect(() => {
    const init = async () => {
      clientRef.current = new LiveClient(
        process.env.API_KEY || '',
        handleTranscript,
        (inV, outV) => { 
            volumeRef.current = { input: inV, output: outV }; 
        },
        () => {},
        () => {},
        () => { if (mountedRef.current) setStatus(ConnectionStatus.DISCONNECTED); },
        (err) => { 
            if (mountedRef.current) setStatus(ConnectionStatus.ERROR);
        }
      );

      // In multi-coach mode, the Live model doesn't need to generate content, 
      // just provide transcription. We keep it connected for silence detection and transcription.
      const instruction = isMultiCoach 
        ? "You are a transcription assistant for a multi-coach session. DO NOT SPEAK. Only provide transcripts of the user audio."
        : scenario.systemInstruction;

      await clientRef.current.connect(instruction, sessionSettings.voiceName);
      if (mountedRef.current) setStatus(ConnectionStatus.CONNECTED);
    };
    init();
    return () => { mountedRef.current = false; clientRef.current?.disconnect(); };
  }, []);

  useLayoutEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [transcripts]);

  return (
    <div className="flex flex-col h-[650px] bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden relative">
      {/* Header */}
      <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-white z-20 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-full ${scenario.color} text-white flex items-center justify-center`}>
                <i className={`fa-solid ${scenario.icon}`}></i>
            </div>
            <div>
                <h3 className="font-bold text-slate-900 leading-tight">{scenario.title}</h3>
                <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase">
                    <div className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-green-500 animate-pulse' : status === ConnectionStatus.PROCESSING ? 'bg-brand-500' : 'bg-slate-300'}`}></div>
                    {isMultiCoach ? `3-Coach Mode: ${status}` : '1-Coach Mode'}
                </div>
            </div>
        </div>
        <button 
            onClick={() => onEndSession({ durationSeconds: (Date.now() - startTime)/1000, fillerWordCount: fillerCount, awkwardPauseCount, hesitationScore: (fillerCount*2 + awkwardPauseCount*5), fillerWordsPerMinute: 0, transcript: transcripts }, false)} 
            className="bg-red-50 text-red-600 px-4 py-2 rounded-lg text-xs font-bold hover:bg-red-100 transition-colors"
        >
            Finish
        </button>
      </div>

      {/* Main View */}
      <div className="flex-1 relative flex flex-col min-h-0 bg-slate-50/30">

         {/* Avatars Area */}
         <div className="flex items-center justify-center gap-4 py-8 pointer-events-none">
            {isMultiCoach ? (
                <>
                    <div className={`transition-all duration-500 transform ${multiCoachStatus.currentCoach === 1 ? 'scale-110' : 'scale-90 opacity-40'}`}>
                        <div className="w-24 h-24 sm:w-32 sm:h-32 bg-white rounded-full shadow-lg border-2 border-brand-500 overflow-hidden relative">
                           <Avatar config={{ ...avatarConfig, gender: 'male' }} isSpeaking={multiCoachStatus.currentCoach === 1 && isSpeaking} />
                           <div className="absolute top-0 inset-x-0 bg-brand-500 text-white text-[8px] font-bold py-0.5 text-center">FLUENCY</div>
                        </div>
                    </div>
                    <div className={`transition-all duration-500 transform ${multiCoachStatus.currentCoach === 2 ? 'scale-110' : 'scale-90 opacity-40'}`}>
                        <div className="w-24 h-24 sm:w-32 sm:h-32 bg-white rounded-full shadow-lg border-2 border-accent-500 overflow-hidden relative">
                           <Avatar config={{ ...avatarConfig, gender: 'female' }} isSpeaking={multiCoachStatus.currentCoach === 2 && isSpeaking} />
                           <div className="absolute top-0 inset-x-0 bg-accent-500 text-white text-[8px] font-bold py-0.5 text-center">CONFIDENCE</div>
                        </div>
                    </div>
                    <div className={`transition-all duration-500 transform ${multiCoachStatus.currentCoach === 3 ? 'scale-110' : 'scale-90 opacity-40'}`}>
                        <div className="w-24 h-24 sm:w-32 sm:h-32 bg-white rounded-full shadow-lg border-2 border-purple-500 overflow-hidden relative">
                           <Avatar config={{ ...avatarConfig, gender: 'female', accessory: 'glasses' }} isSpeaking={multiCoachStatus.currentCoach === 3 && isSpeaking} />
                           <div className="absolute top-0 inset-x-0 bg-purple-500 text-white text-[8px] font-bold py-0.5 text-center">SYNTHESIS</div>
                        </div>
                    </div>
                </>
            ) : (
                <div className="w-48 h-48 sm:w-64 sm:h-64 relative">
                    {isSpeaking && <div className="absolute inset-0 bg-brand-200 rounded-full animate-ping opacity-10"></div>}
                    <Avatar config={avatarConfig} isSpeaking={isSpeaking} />
                </div>
            )}
         </div>

         {/* Sequential Timeline (Only for Multi-Coach) */}
         {isMultiCoach && status === ConnectionStatus.PROCESSING && (
             <div className="px-6 py-2 flex items-center justify-center gap-4 bg-white/80 backdrop-blur border-y border-slate-100 animate-fade-in">
                 {[1, 2, 3].map(step => (
                     <div key={step} className="flex items-center gap-2">
                         <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                             multiCoachStatus.currentCoach === step ? 'bg-brand-600 text-white animate-pulse' : multiCoachStatus.currentCoach! > step ? 'bg-green-500 text-white' : 'bg-slate-200 text-slate-400'
                         }`}>
                             {multiCoachStatus.currentCoach! > step ? <i className="fa-solid fa-check"></i> : step}
                         </div>
                         <span className={`text-[10px] font-bold uppercase tracking-wider ${multiCoachStatus.currentCoach === step ? 'text-brand-600' : 'text-slate-400'}`}>
                             Coach {step}
                         </span>
                         {step < 3 && <div className="w-8 h-px bg-slate-200"></div>}
                     </div>
                 ))}
             </div>
         )}

         {/* Transcripts Area */}
         <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4">
            {transcripts.map((t, idx) => (
                <div key={idx} className={`flex ${t.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                    <div className={`max-w-[85%] rounded-2xl px-4 py-2 text-sm shadow-sm ${
                        t.role === 'user' ? 'bg-slate-900 text-white rounded-br-none' : 
                        t.role === 'coach1' ? 'bg-brand-50 border border-brand-200 text-brand-900 rounded-bl-none' :
                        t.role === 'coach2' ? 'bg-emerald-50 border border-emerald-200 text-emerald-900 rounded-bl-none' :
                        t.role === 'coach3' ? 'bg-purple-50 border border-purple-200 text-purple-900 rounded-bl-none' :
                        'bg-white border border-slate-200 text-slate-800 rounded-bl-none'
                    }`}>
                        <div className="flex items-center gap-2 mb-1">
                            {t.role !== 'user' && t.role !== 'model' && (
                                <span className={`text-[9px] font-bold uppercase tracking-widest ${
                                    t.role === 'coach1' ? 'text-brand-600' : t.role === 'coach2' ? 'text-emerald-600' : 'text-purple-600'
                                }`}>
                                    {t.role === 'coach1' ? 'Fluency' : t.role === 'coach2' ? 'Confidence' : 'Synthesis'}
                                </span>
                            )}
                        </div>
                        {t.text}
                    </div>
                </div>
            ))}
         </div>

         {/* Visualizer Footer */}
         <div className="h-20 bg-white/80 backdrop-blur-md border-t border-slate-100 flex items-center justify-center shrink-0">
            <AudioVisualizer volume={volumeRef.current.input} isActive={status === ConnectionStatus.CONNECTED} />
         </div>
      </div>
    </div>
  );
};

export default ActiveSession;

import React, { useEffect, useRef, useState, useCallback, useMemo, useLayoutEffect } from 'react';
import { Scenario, TranscriptItem, ConnectionStatus, AvatarConfig, SessionReport, SessionSettings, MultiCoachStatus } from '../types';
import { LiveClient } from '../services/liveClient';
import { processMultiCoachTurn } from '../services/multiCoachEngine';
import AudioVisualizer from './AudioVisualizer';
import Avatar from './Avatar';
import { FILLER_WORDS } from '../constants';

interface ActiveSessionProps {
  scenario: Scenario;
  avatarConfig: AvatarConfig;
  sessionSettings: SessionSettings;
  initialTranscript?: TranscriptItem[];
  onEndSession: (report: SessionReport, isSaved?: boolean, audioBlob?: Blob) => void;
}

const FILLER_WORD_REGEX = new RegExp(`\\b(${FILLER_WORDS.join('|')})\\b`, 'gi');
const TRAILING_CONJUNCTION_REGEX = /\b(and|but|so|because|or|which|that|who)\s*[,]?\s*$/i;
const TERMINAL_PUNCTUATION_REGEX = /[.!?]\s*$/;

const ActiveSession: React.FC<ActiveSessionProps> = ({ scenario, avatarConfig, sessionSettings, initialTranscript, onEndSession }) => {
  const isMultiCoach = (sessionSettings.groupSize || 1) > 1;

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.CONNECTING);
  const [transcripts, setTranscripts] = useState<TranscriptItem[]>(initialTranscript || []);
  const volumeRef = useRef({ input: 0, output: 0 });
  const [startTime] = useState<number>(Date.now());
  const [isSpeaking, setIsSpeaking] = useState(false);

  const [multiCoachStatus, setMultiCoachStatus] = useState<MultiCoachStatus>({
    currentCoach: null,
    isComplete: false
  });

  const [fillerCount, setFillerCount] = useState<number>(0);
  const [awkwardPauseCount, setAwkwardPauseCount] = useState<number>(0);
  const [hesitationScore, setHesitationScore] = useState<number>(0);
  const lastActiveTimeRef = useRef<number>(Date.now());
  const [patienceProgress, setPatienceProgress] = useState(0);

  const clientRef = useRef<LiveClient | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const mountedRef = useRef(true);
  const isProcessingRef = useRef(false);

  // Sequential Processing Trigger
  const runMultiCoachSequence = useCallback(async (userInput: string) => {
    if (!mountedRef.current || isProcessingRef.current) return;

    isProcessingRef.current = true;
    setStatus(ConnectionStatus.PROCESSING);

    try {
      const result = await processMultiCoachTurn(
        userInput,
        transcripts.map(t => ({ role: t.role, text: t.text })),
        process.env.API_KEY || '',
        (coach) => setMultiCoachStatus(prev => ({ ...prev, currentCoach: coach }))
      );

      setTranscripts(prev => [
        ...prev,
        { id: `c1_${Date.now()}`, role: 'coach1', text: result.coach1, timestamp: Date.now() },
        { id: `c2_${Date.now()}`, role: 'coach2', text: result.coach2, timestamp: Date.now() },
        { id: `c3_${Date.now()}`, role: 'coach3', text: result.coach3, timestamp: Date.now() },
      ]);

      if (result.audioUrl) {
        const audio = new Audio(result.audioUrl);
        audio.onplay = () => setIsSpeaking(true);
        audio.onended = () => setIsSpeaking(false);
        audio.play();
      }

      setMultiCoachStatus({ currentCoach: null, isComplete: true });
      setStatus(ConnectionStatus.CONNECTED);
    } catch (e) {
      console.error("Multi-coach sequence failed", e);
      setStatus(ConnectionStatus.ERROR);
    } finally {
      isProcessingRef.current = false;
      lastActiveTimeRef.current = Date.now();
    }
  }, [transcripts]);

  const handleTranscript = useCallback((text: string, isUser: boolean, isFinal: boolean) => {
    if (!mountedRef.current) return;

    if (isUser) {
        lastActiveTimeRef.current = Date.now(); // Reset silence timer on every chunk
        const matches = text.match(FILLER_WORD_REGEX);
        if (matches) setFillerCount(f => f + matches.length);

        setTranscripts(prev => {
            const last = prev[prev.length - 1];
            if (last && last.role === 'user') {
                return [...prev.slice(0, -1), { ...last, text: last.text + (text.startsWith(' ') ? text : ' ' + text) }];
            }
            return [...prev, { id: Date.now().toString(), role: 'user', text, timestamp: Date.now() }];
        });
    } else if (!isMultiCoach) {
        setTranscripts(prev => {
            const last = prev[prev.length - 1];
            if (last && last.role === 'model') {
                return [...prev.slice(0, -1), { ...last, text: last.text + text }];
            }
            return [...prev, { id: Date.now().toString(), role: 'model', text, timestamp: Date.now() }];
        });
        setIsSpeaking(true);
        if ((window as any).speakTimeout) clearTimeout((window as any).speakTimeout);
        (window as any).speakTimeout = setTimeout(() => setIsSpeaking(false), 800);
    }
  }, [isMultiCoach]);

  // Silence Detection & Trigger Logic
  useEffect(() => {
    const VOLUME_MIN_THRESHOLD = 0.04;
    const checkActivity = () => {
      if (status !== ConnectionStatus.CONNECTED || isProcessingRef.current) return;

      const now = Date.now();
      const isInputActive = volumeRef.current.input > VOLUME_MIN_THRESHOLD;

      if (isInputActive || isSpeaking) {
        lastActiveTimeRef.current = now;
        setPatienceProgress(0);
        return;
      }

      const silenceDuration = now - lastActiveTimeRef.current;
      const lastUserTranscript = [...transcripts].reverse().find(t => t.role === 'user')?.text || '';

      if (!lastUserTranscript || lastUserTranscript.length < 3) return;

      const isSentenceFinished = TERMINAL_PUNCTUATION_REGEX.test(lastUserTranscript);
      const isTrailing = TRAILING_CONJUNCTION_REGEX.test(lastUserTranscript);

      let threshold = isSentenceFinished ? 2500 : (isTrailing ? 5000 : 3500);
      const progress = Math.min(silenceDuration / threshold, 1);
      setPatienceProgress(progress);

      if (silenceDuration > threshold) {
          if (isMultiCoach) {
              runMultiCoachSequence(lastUserTranscript);
          } else {
              // In single coach mode, we let the Live API handle responses automatically
              // but we reset the timer to prevent multiple awkward pause triggers
              if (!isSentenceFinished) setAwkwardPauseCount(p => p + 1);
              lastActiveTimeRef.current = now;
          }
      }
    };

    const interval = setInterval(checkActivity, 100);
    return () => clearInterval(interval);
  }, [status, isSpeaking, transcripts, isMultiCoach, runMultiCoachSequence]);

  useEffect(() => {
    const init = async () => {
      clientRef.current = new LiveClient(
        process.env.API_KEY || '',
        handleTranscript,
        (inV, outV) => { 
            // Apply slight sensitivity boost to input volume detection
            volumeRef.current = { input: Math.min(inV * 1.5, 1.0), output: outV }; 
        },
        () => {},
        () => {},
        () => { if (mountedRef.current) setStatus(ConnectionStatus.DISCONNECTED); },
        (err) => { 
            if (mountedRef.current) setStatus(ConnectionStatus.ERROR);
        }
      );

      const instruction = isMultiCoach 
        ? "You are a transcription engine for a multi-coach confidence practice. DO NOT SPEAK or generate audio content. Just transcribe user speech using inputAudioTranscription. Your turn is never complete."
        : scenario.systemInstruction;

      await clientRef.current.connect(instruction, sessionSettings.voiceName);
      if (mountedRef.current) setStatus(ConnectionStatus.CONNECTED);
    };
    init();
    return () => { mountedRef.current = false; clientRef.current?.disconnect(); };
  }, []);

  useLayoutEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [transcripts]);

  return (
    <div className="flex flex-col h-[650px] bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden relative">
      <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-white z-20 shrink-0">
        <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-full ${scenario.color} text-white flex items-center justify-center`}>
                <i className={`fa-solid ${scenario.icon}`}></i>
            </div>
            <div>
                <h3 className="font-bold text-slate-900 leading-tight">{scenario.title}</h3>
                <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase">
                    <div className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-green-500 animate-pulse' : status === ConnectionStatus.PROCESSING ? 'bg-brand-500' : 'bg-slate-300'}`}></div>
                    {isMultiCoach ? `3-Coach Mode: ${status}` : '1-Coach Mode'}
                </div>
            </div>
        </div>
        <button 
            onClick={() => onEndSession({ durationSeconds: (Date.now() - startTime)/1000, fillerWordCount: fillerCount, awkwardPauseCount, hesitationScore: (fillerCount*2 + awkwardPauseCount*5), fillerWordsPerMinute: 0, transcript: transcripts }, false)} 
            className="bg-red-50 text-red-600 px-4 py-2 rounded-lg text-xs font-bold hover:bg-red-100 transition-colors"
        >
            Finish
        </button>
      </div>

      <div className="flex-1 relative flex flex-col min-h-0 bg-slate-50/30">
         <div className="flex items-center justify-center gap-4 py-8 pointer-events-none">
            {isMultiCoach ? (
                <>
                    <div className={`transition-all duration-500 transform ${multiCoachStatus.currentCoach === 1 ? 'scale-110' : 'scale-90 opacity-40'}`}>
                        <div className="w-24 h-24 sm:w-32 sm:h-32 bg-white rounded-full shadow-lg border-2 border-brand-500 overflow-hidden relative">
                           <Avatar config={{ ...avatarConfig, gender: 'male' }} isSpeaking={multiCoachStatus.currentCoach === 1 && isSpeaking} />
                           <div className="absolute top-0 inset-x-0 bg-brand-500 text-white text-[8px] font-bold py-0.5 text-center">FLUENCY</div>
                        </div>
                    </div>
                    <div className={`transition-all duration-500 transform ${multiCoachStatus.currentCoach === 2 ? 'scale-110' : 'scale-90 opacity-40'}`}>
                        <div className="w-24 h-24 sm:w-32 sm:h-32 bg-white rounded-full shadow-lg border-2 border-emerald-500 overflow-hidden relative">
                           <Avatar config={{ ...avatarConfig, gender: 'female' }} isSpeaking={multiCoachStatus.currentCoach === 2 && isSpeaking} />
                           <div className="absolute top-0 inset-x-0 bg-emerald-500 text-white text-[8px] font-bold py-0.5 text-center">CONFIDENCE</div>
                        </div>
                    </div>
                    <div className={`transition-all duration-500 transform ${multiCoachStatus.currentCoach === 3 ? 'scale-110' : 'scale-90 opacity-40'}`}>
                        <div className="w-24 h-24 sm:w-32 sm:h-32 bg-white rounded-full shadow-lg border-2 border-purple-500 overflow-hidden relative">
                           <Avatar config={{ ...avatarConfig, gender: 'female', accessory: 'glasses' }} isSpeaking={multiCoachStatus.currentCoach === 3 && isSpeaking} />
                           <div className="absolute top-0 inset-x-0 bg-purple-500 text-white text-[8px] font-bold py-0.5 text-center">SYNTHESIS</div>
                        </div>
                    </div>
                </>
            ) : (
                <div className="w-48 h-48 sm:w-64 sm:h-64 relative">
                    {isSpeaking && <div className="absolute inset-0 bg-brand-200 rounded-full animate-ping opacity-10"></div>}
                    <Avatar config={avatarConfig} isSpeaking={isSpeaking} />
                </div>
            )}
         </div>

         {isMultiCoach && status === ConnectionStatus.PROCESSING && (
             <div className="px-6 py-2 flex items-center justify-center gap-4 bg-white/80 backdrop-blur border-y border-slate-100 animate-fade-in">
                 {[1, 2, 3].map(step => (
                     <div key={step} className="flex items-center gap-2">
                         <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                             multiCoachStatus.currentCoach === step ? 'bg-brand-600 text-white animate-pulse' : multiCoachStatus.currentCoach! > step || multiCoachStatus.isComplete ? 'bg-green-500 text-white' : 'bg-slate-200 text-slate-400'
                         }`}>
                             { (multiCoachStatus.currentCoach && multiCoachStatus.currentCoach > step) || multiCoachStatus.isComplete ? <i className="fa-solid fa-check"></i> : step}
                         </div>
                         <span className={`text-[10px] font-bold uppercase tracking-wider ${multiCoachStatus.currentCoach === step ? 'text-brand-600' : 'text-slate-400'}`}>
                             Coach {step}
                         </span>
                         {step < 3 && <div className="w-8 h-px bg-slate-200"></div>}
                     </div>
                 ))}
             </div>
         )}

         <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4">
            {transcripts.map((t, idx) => (
                <div key={idx} className={`flex ${t.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in-up`}>
                    <div className={`max-w-[85%] rounded-2xl px-4 py-2 text-sm shadow-sm ${
                        t.role === 'user' ? 'bg-slate-900 text-white rounded-br-none' : 
                        t.role === 'coach1' ? 'bg-brand-50 border border-brand-200 text-brand-900 rounded-bl-none' :
                        t.role === 'coach2' ? 'bg-emerald-50 border border-emerald-200 text-emerald-900 rounded-bl-none' :
                        t.role === 'coach3' ? 'bg-purple-50 border border-purple-200 text-purple-900 rounded-bl-none' :
                        'bg-white border border-slate-200 text-slate-800 rounded-bl-none'
                    }`}>
                        <div className="flex items-center gap-2 mb-1">
                            {t.role !== 'user' && t.role !== 'model' && (
                                <span className={`text-[9px] font-bold uppercase tracking-widest ${
                                    t.role === 'coach1' ? 'text-brand-600' : t.role === 'coach2' ? 'text-emerald-600' : 'text-purple-600'
                                }`}>
                                    {t.role === 'coach1' ? 'Fluency' : t.role === 'coach2' ? 'Confidence' : 'Synthesis'}
                                </span>
                            )}
                        </div>
                        {t.text}
                    </div>
                </div>
            ))}
         </div>

         <div className="h-24 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col items-center justify-center shrink-0">
            <div className="relative flex items-center justify-center mb-1">
                <svg className="absolute w-16 h-16 -rotate-90 pointer-events-none">
                    <circle cx="32" cy="32" r="28" fill="none" stroke="currentColor" strokeWidth="2" className="text-slate-100" />
                    <circle
                        cx="32" cy="32" r="28" fill="none" stroke="currentColor" strokeWidth="3"
                        strokeDasharray={175.84}
                        strokeDashoffset={175.84 - (175.84 * patienceProgress)}
                        className="text-brand-500 transition-all duration-300 ease-linear opacity-40"
                        strokeLinecap="round"
                    />
                </svg>
                <AudioVisualizer volume={volumeRef.current.input} isActive={status === ConnectionStatus.CONNECTED} />
            </div>
            <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                {status === ConnectionStatus.CONNECTED ? (patienceProgress > 0.8 ? 'Finishing thought...' : 'Listening...') : 'Processing...'}
            </p>
         </div>
      </div>
    </div>
  );
};

