  const getPhaseText = () => {
    switch (phase) {
      case 'IN': return 'Inhale Deeply';
      case 'HOLD': return 'Hold Your Breath';
      case 'OUT': return 'Exhale Slowly';
      default: return '';
    }
  };

  const getSubText = () => {
    switch (phase) {
