import { GoogleGenAI, Type } from "@google/genai";
import { TranscriptItem, SessionReport } from "../types";

export const generateSessionAnalysis = async (
  transcript: TranscriptItem[],
  scenarioTitle: string,
  apiKey: string
): Promise<Partial<SessionReport>> => {
  const ai = new GoogleGenAI({ apiKey });

  // Extract only user text for analysis to save tokens and focus context
  const userItems = transcript.filter(t => t.role === 'user');
  const userText = userItems.map(t => t.text).join(' ');

  // If there's not enough data, return a neutral/empty report
  if (!userText || userText.trim().length < 15) {
      return {
          fluencyScore: 50,
          vocabularyScore: 50,
          grammarCorrections: [],
          confidenceTips: ["Try speaking more in the next session to receive detailed AI feedback."]
      };
  }

  const prompt = `
    You are an expert language and confidence coach. Analyze the following user transcript from a practice session titled '${scenarioTitle}'.

    User Transcript: "${userText}"

    Your goal is to provide constructive feedback.

    Tasks:
    1. Grammar & Phrasing: Identify up to 3 specific grammatical errors or awkward phrasings. 
       - Provide the original text.
       - Provide a corrected version.
       - Provide a concise explanation of the rule violated (e.g., "Subject-Verb Agreement", "Incorrect Tense", "Wrong Preposition").
    2. Fluency Score (0-100): Rate based on natural flow, sentence structure, and coherence (ignoring simple filler words which are counted separately).
    3. Vocabulary Score (0-100): Rate based on lexical variety and appropriateness for the scenario.
    4. Confidence Tips: Provide 2 specific, actionable tips to improve the user's tone or delivery based on the text content.
  `;

  try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: 'application/json',
          thinkingConfig: { thinkingBudget: 0 }, // Speed optimization
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              fluencyScore: { type: Type.NUMBER },
              vocabularyScore: { type: Type.NUMBER },
              grammarCorrections: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    original: { type: Type.STRING },
                    correction: { type: Type.STRING },
                    explanation: { type: Type.STRING, description: "A concise rule or reason e.g. 'Subject-Verb Agreement'" }
                  }
                }
              },
              confidenceTips: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          }
        }
      });

      const jsonText = response.text;
      if (!jsonText) throw new Error("Empty response from analysis model");

      return JSON.parse(jsonText);
  } catch (e) {
      console.error("Analysis failed", e);
      // Fallback in case of API error
      return {
          fluencyScore: 0,
          vocabularyScore: 0,
          grammarCorrections: [],
          confidenceTips: ["Analysis could not be generated at this time."]
      };
  }
};

import { GoogleGenAI, Modality } from "@google/genai";
import { pcmToWav, decode } from "./audioUtils";

export interface MultiCoachResponse {
  coach1: string;
  coach2: string;
  coach3: string;
  audioUrl?: string;
}

/**
 * Executes a sequential processing chain of three specialist coaches.
 * Each coach builds on the previous one's output and the shared conversation history.
 */
export const processMultiCoachTurn = async (
  userInput: string,
  history: { role: string; text: string }[],
  apiKey: string,
  onProgress: (coach: 1 | 2 | 3) => void
): Promise<MultiCoachResponse> => {
  const ai = new GoogleGenAI({ apiKey });
  const model = 'gemini-3-flash-preview'; // Speed optimization: use Flash instead of Pro

  // State initialization for sequential chain
  let coach1Text = "";
  let coach2Text = "";
  let coach3Text = "";

  // 1. Coach 1: Fluency Expert (Strict focus on mechanics)
  onProgress(1);
  const c1Response = await ai.models.generateContent({
    model,
    contents: `Fluency Expert. Analyze ONLY the user's latest input: "${userInput}". 
    Focus on fillers, pauses, and pace. Speak directly to the user. Keep it brief (max 35 words).`,
    config: {
      systemInstruction: "You are Coach 1, a Fluency Expert. You provide immediate feedback on speech flow.",
      thinkingConfig: { thinkingBudget: 0 } // Speed optimization
    }
  });
  coach1Text = c1Response.text || "I noticed some hesitation in your delivery.";

  // 2. Coach 2: Confidence Coach (Focus on tone and assertiveness)
  onProgress(2);
  const c2Response = await ai.models.generateContent({
    model,
    contents: `Confidence Coach. Build on the session. 
    User said: "${userInput}". 
    Coach 1 said: "${coach1Text}".
    Focus on tone and assertiveness. Speak directly to the user. Keep it brief (max 35 words).`,
    config: {
      systemInstruction: "You are Coach 2, a Confidence Coach. You focus on the user's emotional presence.",
      thinkingConfig: { thinkingBudget: 0 } // Speed optimization
    }
  });
  coach2Text = c2Response.text || "You sound capable, but let's push for more vocal clarity.";

  // 3. Coach 3: Synthesis Coach (Wrap up with actionable steps)
  onProgress(3);
  const c3Response = await ai.models.generateContent({
    model,
    contents: `Synthesis Coach. Summarize progress.
    User: "${userInput}"
    Coach 1: "${coach1Text}"
    Coach 2: "${coach2Text}"
    Provide exactly 3 quick actionable steps. Max 50 words.`,
    config: {
      systemInstruction: "You are Coach 3, the Synthesis Coach. You provide the final wrap-up.",
      thinkingConfig: { thinkingBudget: 0 } // Speed optimization
    }
  });
  coach3Text = c3Response.text || "Next steps: focus on your breathing, use more direct verbs, and maintain this volume.";

  // 4. Multi-Speaker Audio Synthesis
  const ttsPrompt = `TTS the following conversation between three coaches:
  Coach1: ${coach1Text}
  Coach2: ${coach2Text}
  Coach3: ${coach3Text}`;

  let audioUrl: string | undefined;
  try {
    const ttsResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: ttsPrompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        thinkingConfig: { thinkingBudget: 0 }, // Speed optimization
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: 'Coach1', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
              { speaker: 'Coach2', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
              { speaker: 'Coach3', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
            ]
          }
        }
      }
    });

    const base64Audio = ttsResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const wavBlob = pcmToWav(decode(base64Audio), 24000);
      audioUrl = URL.createObjectURL(wavBlob);
    }
  } catch (e) {
    console.warn("Multi-speaker TTS generation failed", e);
  }

  return {
    coach1: coach1Text,
    coach2: coach2Text,
    coach3: coach3Text,
    audioUrl
  };
};

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Resource, UserStats, SessionHistoryItem } from "../types";
import { pcmToWav, decode } from "./audioUtils";

const SCENARIO_COLORS = ['bg-blue-500', 'bg-red-500', 'bg-green-500', 'bg-yellow-500', 'bg-purple-500', 'bg-pink-500', 'bg-indigo-500', 'bg-orange-500', 'bg-teal-500', 'bg-slate-800'];
const ICONS = {
  video: 'fa-play',
  article: 'fa-newspaper',
  podcast: 'fa-headphones'
};

export const fetchDailyRecommendations = async (
  stats: UserStats, 
  history: SessionHistoryItem[], 
  apiKey: string
): Promise<Resource[]> => {
  const ai = new GoogleGenAI({ apiKey });
  const today = new Date().toDateString();

  // 1. Analyze Context from History
  const recentHistory = history.slice(0, 5); // Analyze last 5 sessions
  const lastSession = history.length > 0 ? history[0] : null;
  const lastTopic = lastSession ? lastSession.scenarioTitle : "General Communication";

  // Identify Weaknesses dynamically
  const improvementAreas = [];

  // Filler words check
  const avgFillers = recentHistory.length > 0 
      ? recentHistory.reduce((acc, h) => acc + h.report.fillerWordCount, 0) / recentHistory.length
      : 0;
  if (avgFillers > 6) improvementAreas.push("Reducing filler words (um, uh)");

  // Confidence check
  const nervousCount = recentHistory.filter(h => h.report.dominantEmotion === 'Nervous' || h.report.dominantEmotion === 'Hesitant').length;
  if (nervousCount > 0) improvementAreas.push("Boosting speaking confidence");

  // Vocabulary check (heuristic based on difficulty)
  const basicSessions = recentHistory.filter(h => h.settings.difficulty === 'beginner').length;
  if (basicSessions > 2) improvementAreas.push("Expanding vocabulary complexity");

  // Specific Scenario Focus
  const interviewFocus = recentHistory.some(h => h.scenarioId === 'interview');
  if (interviewFocus) improvementAreas.push("Professional interview responses");

  // Default if no specific data
  if (improvementAreas.length === 0) improvementAreas.push("Advanced conversational nuances");

  const prompt = `
    Today is ${today}.
    Generate 3 distinct, daily coaching resources for a user learning languages and communication skills.

    User Profile:
    - Current Level: ${stats.level} (XP: ${stats.xp})
    - Last Practice Session: "${lastTopic}"
    - Targeted Improvement Areas: ${improvementAreas.join(', ')}.

    Task:
    Return a JSON array of 3 resources. 
    Ensure the titles and descriptions are unique to *today* and tailored to the user's recent activity.
    Vary the topics: include one specific technique, one mindset/confidence tip, and one practice drill.

    Required Types:
    1. 'video' (A visual lesson or drill).
    2. 'podcast' (A conversation or interview).
    3. 'article' (A guide or tip sheet).

    Schema per item:
    - title (String): Engaging and specific.
    - description (String): 1-2 sentences summarizing the value.
    - type (String): 'video', 'podcast', or 'article'.
    - category (String): e.g., "Fluency", "Social Skills", "Business", "Vocab".
    - duration (String): e.g., "3 min", "6 min".
    - xp (Number): Reward amount (30-100).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        thinkingConfig: { thinkingBudget: 0 }, // Speed optimization
        responseSchema: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    title: { type: Type.STRING },
                    description: { type: Type.STRING },
                    type: { type: Type.STRING, enum: ['video', 'podcast', 'article'] },
                    category: { type: Type.STRING },
                    duration: { type: Type.STRING },
                    xp: { type: Type.NUMBER }
                }
            }
        }
      }
    });

    const data = JSON.parse(response.text || '[]');

    return data.map((item: any, index: number) => ({
      ...item,
      id: `daily_${Date.now()}_${index}`,
      icon: ICONS[item.type as keyof typeof ICONS] || 'fa-star',
      imageColor: SCENARIO_COLORS[Math.floor(Math.random() * SCENARIO_COLORS.length)],
      isGenerated: true
    }));

  } catch (e) {
    console.error("Failed to generate recommendations", e);
    return [];
  }
};

export const generateResourceContent = async (resource: Resource, apiKey: string): Promise<Resource['content']> => {
    const ai = new GoogleGenAI({ apiKey });
    const content: Resource['content'] = {};

    // Complexity modifier based on XP rewards (proxy for user level relevance)
    const complexityLevel = resource.xp > 70 ? "Advanced/Professional" : "Beginner/Intermediate";

    try {
        if (resource.type === 'article') {
            const prompt = `
            Write a high-quality, actionable short article titled "${resource.title}".
            Topic Category: ${resource.category}.
            Target Audience: ${complexityLevel} learner.

            Structure:
            1. **The Hook**: Why this matters right now.
            2. **Core Concept**: The main lesson.
            3. **3 Actionable Steps**: Practical things the user can do immediately.
            4. **Pro Tip**: A secret or advanced insight.

            Format: Markdown (use headers, bolding, lists).
            Tone: Encouraging, professional, expert coach.
            Length: ~400 words.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    thinkingConfig: { thinkingBudget: 0 } // Speed optimization
                }
            });
            content.text = response.text || "Content generation failed.";
        } 
        else if (resource.type === 'podcast') {
            const prompt = `
            Create a lively podcast script for 2 hosts (Alex and Sam) discussing "${resource.title}".
            Focus: ${resource.category}.
            Target Audience: ${complexityLevel}.

            Format:
            - Start with a quick energetic intro.
            - Alex explains the problem/topic.
            - Sam provides a solution or a "hack".
            - They roleplay a tiny 10-second example of doing it right vs wrong.
            - Quick summary and sign-off.

            Tone: Fun, fast-paced, like a radio show.
            Length: Approx 2 minutes spoken.
            Output: Just the dialogue text.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-preview-tts',
                contents: [{ parts: [{ text: prompt }] }],
                config: {
                    responseModalities: [Modality.AUDIO],
                    thinkingConfig: { thinkingBudget: 0 }, // Speed optimization
                    speechConfig: {
                        multiSpeakerVoiceConfig: {
                            speakerVoiceConfigs: [
                                { speaker: 'Alex', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } } },
                                { speaker: 'Sam', voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Aoede' } } }
                            ]
                        }
                    }
                }
            });

            const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (audioData) {
                const wavBlob = pcmToWav(decode(audioData));
                content.audioUrl = URL.createObjectURL(wavBlob);
            }
        }
        else if (resource.type === 'video') {
            const scriptPrompt = `
            You are recording a video lesson for "${resource.title}".
            Write the narration script.
            Target Audience: ${complexityLevel}.

            Structure:
            - "Hey everyone, welcome back to FluentFlow."
            - Define the specific problem regarding ${resource.category}.
            - Give one concrete exercise to fix it.
            - "Try this today and let me know how it goes."

            Tone: Youtube Educator (Warm, clear, concise).
            Length: 60 seconds spoken.
            `;

            const audioResponse = await ai.models.generateContent({
                model: 'gemini-2.5-flash-preview-tts',
                contents: [{ parts: [{ text: scriptPrompt }] }],
                config: {
                    responseModalities: [Modality.AUDIO],
                    thinkingConfig: { thinkingBudget: 0 }, // Speed optimization
                    speechConfig: {
                         voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } 
                    }
                }
            });

            const audioData = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (audioData) {
                const wavBlob = pcmToWav(decode(audioData));
                content.audioUrl = URL.createObjectURL(wavBlob);
            }

            const imagePrompt = `
            A modern, flat vector illustration for a video thumbnail about "${resource.title}".
            Style: Corporate Memphis, minimal, vibrant colors (Blue, Orange, White).
            Subject: Abstract representation of ${resource.category}, communication, speaking, or confidence.
            Text free. High quality.
            `;

            try {
                const imageResponse = await ai.models.generateContent({
                    model: 'gemini-2.5-flash-image',
                    contents: { parts: [{ text: imagePrompt }] },
                });

                const parts = imageResponse.candidates?.[0]?.content?.parts;
                let imageData;
                if (parts) {
                    for (const part of parts) {
                        if (part.inlineData) {
                            imageData = part.inlineData.data;
                            break;
                        }
                    }
                }

                if (imageData) {
                     content.imageUrl = `data:image/jpeg;base64,${imageData}`;
                }
            } catch (imgErr) {
                console.warn("Image gen failed", imgErr);
            }
        }
    } catch (e) {
        console.error("Content generation failed", e);
        throw e;
    }

    return content;
};

import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createBlob, decode, decodeAudioData, float32ToWav } from './audioUtils';
import { AUDIO_SAMPLE_RATE_INPUT, AUDIO_SAMPLE_RATE_OUTPUT } from '../constants';

export type TranscriptCallback = (text: string, isUser: boolean, isFinal: boolean) => void;
export type VolumeCallback = (inputVolume: number, outputVolume: number) => void;
export type GroundingCallback = (metadata: any) => void;
export type AnalysisCallback = (emotion: string, intent: string) => void;
export type BreathCallback = (phase: 'IN' | 'HOLD' | 'OUT' | 'END') => void;

const ANALYSIS_REGEX = /\[\[E:(\w+)\]\](?:\[\[I:(\w+)\]\])?/;
const BREATH_REGEX = /\[\[B:(\w+)\]\]/;

export class LiveClient {
  private ai: GoogleGenAI;
  private model: string = 'gemini-2.5-flash-native-audio-preview-12-2025';
  private inputAudioContext: AudioContext | null = null;
  private outputAudioContext: AudioContext | null = null;
  private mediaStream: MediaStream | null = null;
  private processor: ScriptProcessorNode | null = null;
  private source: MediaStreamAudioSourceNode | null = null;

  private inputAnalyser: AnalyserNode | null = null;
  private outputAnalyser: AnalyserNode | null = null;
  private animationFrameId: number | null = null;

  private nextStartTime: number = 0;
  private activeSources: Set<AudioBufferSourceNode> = new Set();

  // Recording Mastering Chain
  private recordingProcessor: ScriptProcessorNode | null = null;
  private recordingHighPass: BiquadFilterNode | null = null;
  private recordingCompressor: DynamicsCompressorNode | null = null;
  private recordingLimiter: DynamicsCompressorNode | null = null;
  private recordedChunks: Float32Array[] = [];
  private isRecording: boolean = false;

  // Analysis State
  private currentModelTurnText: string = '';
  private hasEmittedAnalysisForTurn: boolean = false;

  // Callbacks
  private onTranscript: TranscriptCallback;
  private onVolume: VolumeCallback;
  private onGrounding: GroundingCallback;
  private onAnalysis: AnalysisCallback;
  private onBreath: BreathCallback;
  private onClose: () => void;
  private onError: (err: Error) => void;

  private sessionPromise: Promise<any> | null = null;

  constructor(
    apiKey: string, 
    onTranscript: TranscriptCallback, 
    onVolume: VolumeCallback,
    onGrounding: GroundingCallback,
    onAnalysis: AnalysisCallback,
    onBreath: BreathCallback,
    onClose: () => void,
    onError: (err: Error) => void
  ) {
    this.ai = new GoogleGenAI({ apiKey });
    this.onTranscript = onTranscript;
    this.onVolume = onVolume;
    this.onGrounding = onGrounding;
    this.onAnalysis = onAnalysis;
    this.onBreath = onBreath;
    this.onClose = onClose;
    this.onError = onError;
  }

  public async connect(systemInstruction: string, voiceName: string) {
    try {
      this.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: AUDIO_SAMPLE_RATE_INPUT,
      });
      this.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: AUDIO_SAMPLE_RATE_OUTPUT,
      });

      this.mediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });

      this.inputAnalyser = this.inputAudioContext.createAnalyser();
      this.inputAnalyser.fftSize = 256;
      this.inputAnalyser.smoothingTimeConstant = 0.1;

      this.outputAnalyser = this.outputAudioContext.createAnalyser();
      this.outputAnalyser.fftSize = 256;
      this.outputAnalyser.smoothingTimeConstant = 0.1;
      this.outputAnalyser.connect(this.outputAudioContext.destination);

      this.setupRecorder();

      const promise = this.ai.live.connect({
        model: this.model,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName } },
          },
          systemInstruction: systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          // Optimization: Removed tools like googleSearch to reduce planning latency
          thinkingConfig: { thinkingBudget: 0 } 
        },
        callbacks: {
          onopen: () => {
            this.startAudioInput(promise);
            this.startAnalysisLoop();
          },
          onmessage: (msg: LiveServerMessage) => this.handleMessage(msg),
          onclose: () => {
            this.onClose();
          },
          onerror: (err: ErrorEvent) => {
            this.onError(new Error("Connection error: " + err.message));
          }
        }
      });

      this.sessionPromise = promise;
    } catch (error) {
      this.onError(error as Error);
    }
  }

  private setupRecorder() {
    if (!this.outputAudioContext || !this.mediaStream) return;

    const now = this.outputAudioContext.currentTime;

    // 1. High Pass Filter - Remove sub-80Hz noise/rumble
    this.recordingHighPass = this.outputAudioContext.createBiquadFilter();
    this.recordingHighPass.type = 'highpass';
    this.recordingHighPass.frequency.setValueAtTime(80, now);
    this.recordingHighPass.Q.setValueAtTime(0.7, now);

    // 2. Main Vocal Compressor - Smooth out dynamic range
    this.recordingCompressor = this.outputAudioContext.createDynamicsCompressor();
    this.recordingCompressor.threshold.setValueAtTime(-18, now);
    this.recordingCompressor.knee.setValueAtTime(12, now);
    this.recordingCompressor.ratio.setValueAtTime(4, now);
    this.recordingCompressor.attack.setValueAtTime(0.01, now);
    this.recordingCompressor.release.setValueAtTime(0.2, now);

    // 3. Peak Limiter - Prevent clipping and ensure high perceived volume
    this.recordingLimiter = this.outputAudioContext.createDynamicsCompressor();
    this.recordingLimiter.threshold.setValueAtTime(-2, now);
    this.recordingLimiter.knee.setValueAtTime(0, now);
    this.recordingLimiter.ratio.setValueAtTime(20, now);
    this.recordingLimiter.attack.setValueAtTime(0.001, now);
    this.recordingLimiter.release.setValueAtTime(0.05, now);

    // Capture Processor - Reduced buffer size to 2048 for faster capture processing
    this.recordingProcessor = this.outputAudioContext.createScriptProcessor(2048, 1, 1);
    this.recordedChunks = [];
    this.isRecording = true;

    this.recordingProcessor.onaudioprocess = (e) => {
      if (this.isRecording) {
        const inputData = e.inputBuffer.getChannelData(0);
        this.recordedChunks.push(new Float32Array(inputData));
      }
    };

    // 5. Build Mastering Chain: Sources -> Filter -> Compressor -> Limiter -> Processor
    const micSource = this.outputAudioContext.createMediaStreamSource(this.mediaStream);
    const micGain = this.outputAudioContext.createGain();
    micGain.gain.value = 1.0; 

    micSource.connect(micGain);
    micGain.connect(this.recordingHighPass);
    this.recordingHighPass.connect(this.recordingCompressor);
    this.recordingCompressor.connect(this.recordingLimiter);
    this.recordingLimiter.connect(this.recordingProcessor);
    this.recordingProcessor.connect(this.outputAudioContext.destination);
  }

  public getSessionRecording(): globalThis.Blob | null {
    if (this.recordedChunks.length === 0) return null;

    // Post-processing: Normalize peak volume to -1dB across entire session
    let maxVal = 0;
    for (const chunk of this.recordedChunks) {
      for (let i = 0; i < chunk.length; i++) {
        const absVal = Math.abs(chunk[i]);
        if (absVal > maxVal) maxVal = absVal;
      }
    }

    const targetPeak = 0.9; // Normalize to approx -1dB
    if (maxVal > 0) {
      const scale = targetPeak / maxVal;
      for (const chunk of this.recordedChunks) {
        for (let i = 0; i < chunk.length; i++) {
          chunk[i] *= scale;
        }
      }
    }

    return float32ToWav(this.recordedChunks, AUDIO_SAMPLE_RATE_OUTPUT);
  }

  private startAnalysisLoop() {
    const dataArray = new Uint8Array(128);

    const analyze = () => {
      let inputVol = 0;
      let outputVol = 0;

      if (this.inputAnalyser) {
        this.inputAnalyser.getByteTimeDomainData(dataArray);
        let sum = 0;
        for(let i = 0; i < dataArray.length; i++) {
          const x = (dataArray[i] - 128) / 128.0;
          sum += x * x;
        }
        inputVol = Math.sqrt(sum / dataArray.length);
      }

      if (this.outputAnalyser) {
        this.outputAnalyser.getByteTimeDomainData(dataArray);
        let sum = 0;
        for(let i = 0; i < dataArray.length; i++) {
          const x = (dataArray[i] - 128) / 128.0;
          sum += x * x;
        }
        outputVol = Math.sqrt(sum / dataArray.length);
      }

      this.onVolume(inputVol, outputVol);
      this.animationFrameId = requestAnimationFrame(analyze);
    };

    analyze();
  }

  private startAudioInput(sessionPromise: Promise<any>) {
    if (!this.inputAudioContext || !this.mediaStream || !this.inputAnalyser) return;

    this.source = this.inputAudioContext.createMediaStreamSource(this.mediaStream);
    // Reduced buffer size to 2048 to minimize input latency
    this.processor = this.inputAudioContext.createScriptProcessor(2048, 1, 1);

    this.processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);
      const pcmBlob = createBlob(inputData);
      sessionPromise.then((session) => {
        session.sendRealtimeInput({ media: pcmBlob });
      });
    };

    this.source.connect(this.inputAnalyser);
    this.inputAnalyser.connect(this.processor);
    this.processor.connect(this.inputAudioContext.destination);
  }

  private async handleMessage(message: LiveServerMessage) {
    const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData && this.outputAudioContext) {
      this.playAudio(audioData);
    }

    const userTranscript = message.serverContent?.inputTranscription?.text;
    if (userTranscript) {
      this.onTranscript(userTranscript, true, !!message.serverContent?.turnComplete);
    }

    const modelTranscriptChunk = message.serverContent?.outputTranscription?.text;
    if (modelTranscriptChunk) {
       this.currentModelTurnText += modelTranscriptChunk;

       // Handle Breath Tags
       const breathMatch = this.currentModelTurnText.match(BREATH_REGEX);
       if (breathMatch) {
         this.onBreath(breathMatch[1] as any);
         // Clear tag so it doesn't match again immediately in this turn
         this.currentModelTurnText = this.currentModelTurnText.replace(BREATH_REGEX, '');
       }

       if (!this.hasEmittedAnalysisForTurn) {
          const match = this.currentModelTurnText.match(ANALYSIS_REGEX);
          if (match) {
            const emotion = match[1];
            const intent = match[2] || 'Neutral';
            this.onAnalysis(emotion, intent);
            this.hasEmittedAnalysisForTurn = true;
          }
       }

       this.onTranscript(modelTranscriptChunk, false, !!message.serverContent?.turnComplete);
    }

    const groundingMetadata = message.serverContent?.groundingMetadata;
    if (groundingMetadata) {
      this.onGrounding(groundingMetadata);
    }

    if (message.serverContent?.interrupted) {
      this.stopPlayback();
    }

    if (message.serverContent?.turnComplete) {
       this.currentModelTurnText = '';
       this.hasEmittedAnalysisForTurn = false;
    }
  }

  private async playAudio(base64Data: string) {
    if (!this.outputAudioContext || !this.outputAnalyser || !this.recordingCompressor) return;

    const bytes = decode(base64Data);
    const buffer = await decodeAudioData(bytes, this.outputAudioContext, AUDIO_SAMPLE_RATE_OUTPUT, 1);

    this.nextStartTime = Math.max(this.nextStartTime, this.outputAudioContext.currentTime);

    const source = this.outputAudioContext.createBufferSource();
    source.buffer = buffer;

    source.connect(this.outputAnalyser);

    // Connect AI response to the high-pass filtered recording chain
    if (this.recordingHighPass) {
      source.connect(this.recordingHighPass);
    }

    source.addEventListener('ended', () => {
      this.activeSources.delete(source);
    });

    source.start(this.nextStartTime);
    this.nextStartTime += buffer.duration;
    this.activeSources.add(source);
  }

  private stopPlayback() {
    this.activeSources.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    this.activeSources.clear();
    this.nextStartTime = this.outputAudioContext?.currentTime || 0;
  }

  public async disconnect() {
    this.isRecording = false;

    if (this.animationFrameId) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = null;
    }

    if (this.sessionPromise) {
      try {
          const session = await this.sessionPromise;
          session.close();
      } catch (e) {
          console.debug('Error closing session', e);
      }
      this.sessionPromise = null;
    }

    this.stopPlayback();

    if (this.processor) {
      this.processor.disconnect();
      this.processor = null;
    }
    if (this.recordingProcessor) {
      this.recordingProcessor.disconnect();
      this.recordingProcessor = null;
    }
    if (this.recordingHighPass) {
      this.recordingHighPass.disconnect();
      this.recordingHighPass = null;
    }
    if (this.recordingCompressor) {
      this.recordingCompressor.disconnect();
      this.recordingCompressor = null;
    }
    if (this.recordingLimiter) {
      this.recordingLimiter.disconnect();
      this.recordingLimiter = null;
    }
    if (this.source) {
      this.source.disconnect();
      this.source = null;
    }
    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach(track => track.stop());
      this.mediaStream = null;
    }
    if (this.inputAudioContext) {
      await this.inputAudioContext.close();
      this.inputAudioContext = null;
    }
    if (this.outputAudioContext) {
      await this.outputAudioContext.close();
      this.outputAudioContext = null;
    }

    this.onVolume(0, 0);
  }
}

import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createBlob, decode, decodeAudioData, float32ToWav } from './audioUtils';
import { AUDIO_SAMPLE_RATE_INPUT, AUDIO_SAMPLE_RATE_OUTPUT } from '../constants';

export type TranscriptCallback = (text: string, isUser: boolean, isFinal: boolean) => void;
export type VolumeCallback = (inputVolume: number, outputVolume: number) => void;
export type GroundingCallback = (metadata: any) => void;
export type AnalysisCallback = (emotion: string, intent: string) => void;
export type BreathCallback = (phase: 'IN' | 'HOLD' | 'OUT' | 'END') => void;

const ANALYSIS_REGEX = /\[\[E:([^\]]+)\]\](?:\[\[I:([^\]]+)\]\])?/g;
const BREATH_REGEX = /\[\[B:(\w+)\]\]/g;

export class LiveClient {
  private ai: GoogleGenAI;
  private model: string = 'gemini-2.5-flash-native-audio-preview-12-2025';
  private inputAudioContext: AudioContext | null = null;
  private outputAudioContext: AudioContext | null = null;
  private mediaStream: MediaStream | null = null;
  private processor: ScriptProcessorNode | null = null;
  private source: MediaStreamAudioSourceNode | null = null;

  private inputAnalyser: AnalyserNode | null = null;
  private outputAnalyser: AnalyserNode | null = null;
  private animationFrameId: number | null = null;

  private nextStartTime: number = 0;
  private activeSources: Set<AudioBufferSourceNode> = new Set();

  // Recording Mastering Chain
  private recordingProcessor: ScriptProcessorNode | null = null;
  private recordingHighPass: BiquadFilterNode | null = null;
  private recordingCompressor: DynamicsCompressorNode | null = null;
  private recordingLimiter: DynamicsCompressorNode | null = null;
  private recordedChunks: Float32Array[] = [];
  private isRecording: boolean = false;

  // Analysis State
  private currentModelTurnText: string = '';

  // Callbacks
  private onTranscript: TranscriptCallback;
  private onVolume: VolumeCallback;
  private onGrounding: GroundingCallback;
  private onAnalysis: AnalysisCallback;
  private onBreath: BreathCallback;
  private onClose: () => void;
  private onError: (err: Error) => void;

  private sessionPromise: Promise<any> | null = null;

  constructor(
    apiKey: string, 
    onTranscript: TranscriptCallback, 
    onVolume: VolumeCallback,
    onGrounding: GroundingCallback,
    onAnalysis: AnalysisCallback,
    onBreath: BreathCallback,
    onClose: () => void,
    onError: (err: Error) => void
  ) {
    this.ai = new GoogleGenAI({ apiKey });
    this.onTranscript = onTranscript;
    this.onVolume = onVolume;
    this.onGrounding = onGrounding;
    this.onAnalysis = onAnalysis;
    this.onBreath = onBreath;
    this.onClose = onClose;
    this.onError = onError;
  }

  public async connect(systemInstruction: string, voiceName: string) {
    try {
      this.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: AUDIO_SAMPLE_RATE_INPUT,
      });
      this.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: AUDIO_SAMPLE_RATE_OUTPUT,
      });

      this.mediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });

      this.inputAnalyser = this.inputAudioContext.createAnalyser();
      this.inputAnalyser.fftSize = 256;
      this.inputAnalyser.smoothingTimeConstant = 0.1;

      this.outputAnalyser = this.outputAudioContext.createAnalyser();
      this.outputAnalyser.fftSize = 256;
      this.outputAnalyser.smoothingTimeConstant = 0.1;
      this.outputAnalyser.connect(this.outputAudioContext.destination);

      this.setupRecorder();

      const promise = this.ai.live.connect({
        model: this.model,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName } },
          },
          systemInstruction: systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          thinkingConfig: { thinkingBudget: 0 } 
        },
        callbacks: {
          onopen: () => {
            this.startAudioInput(promise);
            this.startAnalysisLoop();
          },
          onmessage: (msg: LiveServerMessage) => this.handleMessage(msg),
          onclose: () => {
            this.onClose();
          },
          onerror: (err: ErrorEvent) => {
            this.onError(new Error("Connection error: " + err.message));
          }
        }
      });

      this.sessionPromise = promise;
    } catch (error) {
      this.onError(error as Error);
    }
  }

  private setupRecorder() {
    if (!this.outputAudioContext || !this.mediaStream) return;

    const now = this.outputAudioContext.currentTime;

    this.recordingHighPass = this.outputAudioContext.createBiquadFilter();
    this.recordingHighPass.type = 'highpass';
    this.recordingHighPass.frequency.setValueAtTime(80, now);
    this.recordingHighPass.Q.setValueAtTime(0.7, now);

    this.recordingCompressor = this.outputAudioContext.createDynamicsCompressor();
    this.recordingCompressor.threshold.setValueAtTime(-18, now);
    this.recordingCompressor.knee.setValueAtTime(12, now);
    this.recordingCompressor.ratio.setValueAtTime(4, now);
    this.recordingCompressor.attack.setValueAtTime(0.01, now);
    this.recordingCompressor.release.setValueAtTime(0.2, now);

    this.recordingLimiter = this.outputAudioContext.createDynamicsCompressor();
    this.recordingLimiter.threshold.setValueAtTime(-2, now);
    this.recordingLimiter.knee.setValueAtTime(0, now);
    this.recordingLimiter.ratio.setValueAtTime(20, now);
    this.recordingLimiter.attack.setValueAtTime(0.001, now);
    this.recordingLimiter.release.setValueAtTime(0.05, now);

    this.recordingProcessor = this.outputAudioContext.createScriptProcessor(2048, 1, 1);
    this.recordedChunks = [];
    this.isRecording = true;

    this.recordingProcessor.onaudioprocess = (e) => {
      if (this.isRecording) {
        const inputData = e.inputBuffer.getChannelData(0);
        this.recordedChunks.push(new Float32Array(inputData));
      }
    };

    const micSource = this.outputAudioContext.createMediaStreamSource(this.mediaStream);
    const micGain = this.outputAudioContext.createGain();
    micGain.gain.value = 1.0; 

    micSource.connect(micGain);
    micGain.connect(this.recordingHighPass);
    this.recordingHighPass.connect(this.recordingCompressor);
    this.recordingCompressor.connect(this.recordingLimiter);
    this.recordingLimiter.connect(this.recordingProcessor);
    this.recordingProcessor.connect(this.outputAudioContext.destination);
  }

  public getSessionRecording(): globalThis.Blob | null {
    if (this.recordedChunks.length === 0) return null;

    let maxVal = 0;
    for (const chunk of this.recordedChunks) {
      for (let i = 0; i < chunk.length; i++) {
        const absVal = Math.abs(chunk[i]);
        if (absVal > maxVal) maxVal = absVal;
      }
    }

    const targetPeak = 0.9;
    if (maxVal > 0) {
      const scale = targetPeak / maxVal;
      for (const chunk of this.recordedChunks) {
        for (let i = 0; i < chunk.length; i++) {
          chunk[i] *= scale;
        }
      }
    }

    return float32ToWav(this.recordedChunks, AUDIO_SAMPLE_RATE_OUTPUT);
  }

  private startAnalysisLoop() {
    const dataArray = new Uint8Array(128);

    const analyze = () => {
      let inputVol = 0;
      let outputVol = 0;

      if (this.inputAnalyser) {
        this.inputAnalyser.getByteTimeDomainData(dataArray);
        let sum = 0;
        for(let i = 0; i < dataArray.length; i++) {
          const x = (dataArray[i] - 128) / 128.0;
          sum += x * x;
        }
        inputVol = Math.sqrt(sum / dataArray.length);
      }

      if (this.outputAnalyser) {
        this.outputAnalyser.getByteTimeDomainData(dataArray);
        let sum = 0;
        for(let i = 0; i < dataArray.length; i++) {
          const x = (dataArray[i] - 128) / 128.0;
          sum += x * x;
        }
        outputVol = Math.sqrt(sum / dataArray.length);
      }

      this.onVolume(inputVol, outputVol);
      this.animationFrameId = requestAnimationFrame(analyze);
    };

    analyze();
  }

  private startAudioInput(sessionPromise: Promise<any>) {
    if (!this.inputAudioContext || !this.mediaStream || !this.inputAnalyser) return;

    this.source = this.inputAudioContext.createMediaStreamSource(this.mediaStream);
    this.processor = this.inputAudioContext.createScriptProcessor(2048, 1, 1);

    this.processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);
      const pcmBlob = createBlob(inputData);
      sessionPromise.then((session) => {
        session.sendRealtimeInput({ media: pcmBlob });
      });
    };

    this.source.connect(this.inputAnalyser);
    this.inputAnalyser.connect(this.processor);
    this.processor.connect(this.inputAudioContext.destination);
  }

  private async handleMessage(message: LiveServerMessage) {
    const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (audioData && this.outputAudioContext) {
      this.playAudio(audioData);
    }

    const userTranscript = message.serverContent?.inputTranscription?.text;
    if (userTranscript) {
      this.onTranscript(userTranscript, true, !!message.serverContent?.turnComplete);
    }

    const modelTranscriptChunk = message.serverContent?.outputTranscription?.text;
    if (modelTranscriptChunk) {
       this.currentModelTurnText += modelTranscriptChunk;

       // Detect and emit emotion/intent analysis from chunk
       let analysisMatch;
       const analysisRegexClone = new RegExp(ANALYSIS_REGEX); // Reset index
       while ((analysisMatch = analysisRegexClone.exec(this.currentModelTurnText)) !== null) {
         this.onAnalysis(analysisMatch[1], analysisMatch[2] || 'Neutral');
       }

       // Handle Breath Tags
       let breathMatch;
       const breathRegexClone = new RegExp(BREATH_REGEX);
       while ((breathMatch = breathRegexClone.exec(this.currentModelTurnText)) !== null) {
         this.onBreath(breathMatch[1] as any);
       }

       this.onTranscript(modelTranscriptChunk, false, !!message.serverContent?.turnComplete);
    }

    const groundingMetadata = message.serverContent?.groundingMetadata;
    if (groundingMetadata) {
      this.onGrounding(groundingMetadata);
    }

    if (message.serverContent?.interrupted) {
      this.stopPlayback();
    }

    if (message.serverContent?.turnComplete) {
       this.currentModelTurnText = '';
    }
  }

  private async playAudio(base64Data: string) {
    if (!this.outputAudioContext || !this.outputAnalyser || !this.recordingCompressor) return;

    const bytes = decode(base64Data);
    const buffer = await decodeAudioData(bytes, this.outputAudioContext, AUDIO_SAMPLE_RATE_OUTPUT, 1);

    this.nextStartTime = Math.max(this.nextStartTime, this.outputAudioContext.currentTime);

    const source = this.outputAudioContext.createBufferSource();
    source.buffer = buffer;

    source.connect(this.outputAnalyser);

    if (this.recordingHighPass) {
      source.connect(this.recordingHighPass);
    }

    source.addEventListener('ended', () => {
      this.activeSources.delete(source);
    });

    source.start(this.nextStartTime);
    this.nextStartTime += buffer.duration;
    this.activeSources.add(source);
  }

  private stopPlayback() {
    this.activeSources.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    this.activeSources.clear();
    this.nextStartTime = this.outputAudioContext?.currentTime || 0;
  }

  public async disconnect() {
    this.isRecording = false;

    if (this.animationFrameId) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = null;
    }

    if (this.sessionPromise) {
      try {
          const session = await this.sessionPromise;
          session.close();
      } catch (e) {
          console.debug('Error closing session', e);
      }
      this.sessionPromise = null;
    }

    this.stopPlayback();

    if (this.processor) {
      this.processor.disconnect();
      this.processor = null;
    }
    if (this.recordingProcessor) {
      this.recordingProcessor.disconnect();
      this.recordingProcessor = null;
    }
    if (this.recordingHighPass) {
      this.recordingHighPass.disconnect();
      this.recordingHighPass = null;
    }
    if (this.recordingCompressor) {
      this.recordingCompressor.disconnect();
      this.recordingCompressor = null;
    }
    if (this.recordingLimiter) {
      this.recordingLimiter.disconnect();
      this.recordingLimiter = null;
    }
    if (this.source) {
      this.source.disconnect();
      this.source = null;
    }
    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach(track => track.stop());
      this.mediaStream = null;
    }
    if (this.inputAudioContext) {
      await this.inputAudioContext.close();
      this.inputAudioContext = null;
    }
    if (this.outputAudioContext) {
      await this.outputAudioContext.close();
      this.outputAudioContext = null;
    }

    this.onVolume(0, 0);
  }
}

import React, { useEffect, useRef, useState, useCallback, useLayoutEffect } from 'react';
import { Scenario, TranscriptItem, ConnectionStatus, AvatarConfig, SessionReport, SessionSettings } from '../types';
import { LiveClient } from '../services/liveClient';
import AudioVisualizer from './AudioVisualizer';
import Avatar from './Avatar';
import BreathingGuide from './BreathingGuide';
import { FILLER_WORDS } from '../constants';

interface ActiveSessionProps {
  scenario: Scenario;
  avatarConfig: AvatarConfig;
  sessionSettings: SessionSettings;
  initialTranscript?: TranscriptItem[];
  onEndSession: (report: SessionReport, isSaved?: boolean, audioBlob?: Blob) => void;
}

const FILLER_WORD_REGEX = new RegExp(`\\b(${FILLER_WORDS.join('|')})\\b`, 'gi');
const TAG_CLEAN_REGEX = /\[\[(E|I|B):[^\]]+\]\]/g;
const PRONUNCIATION_TIP_REGEX = /Tip:\s*['"“]?([^'"“”]+)['"”]?\s*-\s*([^[\n\r\]]+)/i;

const EMOTION_ICONS: Record<string, string> = {
    'Confident': 'fa-shield-halved text-green-500',
    'Hesitant': 'fa-pause text-yellow-500',
    'Nervous': 'fa-heart-pulse text-orange-500',
    'Excited': 'fa-bolt text-yellow-400',
    'Neutral': 'fa-face-meh text-slate-400',
    'Frustrated': 'fa-fire-alt text-red-500'
};

const ActiveSession: React.FC<ActiveSessionProps> = ({ scenario, avatarConfig, sessionSettings, initialTranscript, onEndSession }) => {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.CONNECTING);
  const [transcripts, setTranscripts] = useState<TranscriptItem[]>(initialTranscript || []);
  const volumeRef = useRef({ input: 0, output: 0 });
  const [startTime] = useState<number>(Date.now());
  const [isSpeaking, setIsSpeaking] = useState(false);

  const [fillerCount, setFillerCount] = useState<number>(0);
  const [awkwardPauseCount, setAwkwardPauseCount] = useState<number>(0);
  const [pronunciationTips, setPronunciationTips] = useState<{word: string, correction: string, id: string}[]>([]);
  const [perception, setPerception] = useState<{emotion: string, intent: string} | null>(null);
  const lastActivityRef = useRef<number>(Date.now());

  // Breathing Exercise State
  const [breathPhase, setBreathPhase] = useState<'IN' | 'HOLD' | 'OUT' | 'END'>('END');

  const clientRef = useRef<LiveClient | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const mountedRef = useRef(true);

  const handleTranscript = useCallback((text: string, isUser: boolean, isFinal: boolean) => {
    if (!mountedRef.current) return;

    // Clean text from all tags including metadata
    const cleanText = text.replace(TAG_CLEAN_REGEX, '').trim();
    if (!cleanText) return;

    if (isUser) {
        lastActivityRef.current = Date.now();
        const matches = cleanText.match(FILLER_WORD_REGEX);
        if (matches) setFillerCount(f => f + matches.length);

        setTranscripts(prev => {
            const last = prev[prev.length - 1];
            if (last && last.role === 'user') {
                return [...prev.slice(0, -1), { ...last, text: last.text + (cleanText.startsWith(' ') ? cleanText : ' ' + cleanText) }];
            }
            return [...prev, { id: Date.now().toString(), role: 'user', text: cleanText, timestamp: Date.now() }];
        });
    } else {
        // Parse Pronunciation Tip if present in model output
        const tipMatch = cleanText.match(PRONUNCIATION_TIP_REGEX);
        if (tipMatch) {
            const word = tipMatch[1].trim();
            const correction = tipMatch[2].trim();
            setPronunciationTips(prev => {
                if (prev.length > 0 && prev[0].word.toLowerCase() === word.toLowerCase()) return prev;
                return [{ word, correction, id: Date.now().toString() }, ...prev].slice(0, 10); 
            });
        }

        setTranscripts(prev => {
            const last = prev[prev.length - 1];
            if (last && last.role === 'model') {
                return [...prev.slice(0, -1), { ...last, text: last.text + cleanText }];
            }
            return [...prev, { id: Date.now().toString(), role: 'model', text: cleanText, timestamp: Date.now() }];
        });
        setIsSpeaking(true);
        if ((window as any).speakTimeout) clearTimeout((window as any).speakTimeout);
        (window as any).speakTimeout = setTimeout(() => setIsSpeaking(false), 800);
    }
  }, []);

  // Detect Awkward Pauses
  useEffect(() => {
    const NOISE_THRESHOLD = 0.05;
    const PAUSE_THRESHOLD_MS = 3800; 

    const interval = setInterval(() => {
      if (status !== ConnectionStatus.CONNECTED || isSpeaking || breathPhase !== 'END') {
        lastActivityRef.current = Date.now();
        return;
      }

      const isUserTalking = volumeRef.current.input > NOISE_THRESHOLD;
      if (isUserTalking) {
        lastActivityRef.current = Date.now();
      } else {
        const silenceTime = Date.now() - lastActivityRef.current;
        if (silenceTime > PAUSE_THRESHOLD_MS && silenceTime < PAUSE_THRESHOLD_MS + 300) {
          setAwkwardPauseCount(c => c + 1);
        }
      }
    }, 200);

    return () => clearInterval(interval);
  }, [status, isSpeaking, breathPhase]);

  useEffect(() => {
    const init = async () => {
      clientRef.current = new LiveClient(
        process.env.API_KEY || '',
        handleTranscript,
        (inV, outV) => { 
            volumeRef.current = { input: inV, output: outV }; 
        },
        () => {}, // onGrounding
        (emotion, intent) => {
            if (mountedRef.current) setPerception({ emotion, intent });
        },
        (phase) => {
            if (mountedRef.current) setBreathPhase(phase);
        },
        () => { if (mountedRef.current) setStatus(ConnectionStatus.DISCONNECTED); },
        (err) => { 
            if (mountedRef.current) setStatus(ConnectionStatus.ERROR);
        }
      );

      await clientRef.current.connect(scenario.systemInstruction, sessionSettings.voiceName);
      if (mountedRef.current) setStatus(ConnectionStatus.CONNECTED);
    };
    init();
    return () => { 
      mountedRef.current = false; 
      clientRef.current?.disconnect(); 
    };
  }, [scenario.systemInstruction, sessionSettings.voiceName, handleTranscript]);

  useLayoutEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [transcripts]);

  const handleFinish = () => {
    const durationSeconds = (Date.now() - startTime) / 1000;
    const durationMinutes = Math.max(durationSeconds / 60, 0.1);
    const fpm = fillerCount / durationMinutes;
    const apm = awkwardPauseCount / durationMinutes;
    const hesitationScore = Math.round((fpm * 1.5) + (apm * 5.5));

    onEndSession({ 
      durationSeconds, 
      fillerWordCount: fillerCount, 
      awkwardPauseCount, 
      hesitationScore, 
      fillerWordsPerMinute: Number(fpm.toFixed(1)), 
      transcript: transcripts,
      dominantEmotion: perception?.emotion,
      dominantIntent: perception?.intent
    }, false, clientRef.current?.getSessionRecording() || undefined);
  };

  const latestTip = pronunciationTips[0];

  return (
    <div className="flex flex-col lg:flex-row h-[750px] lg:h-[650px] bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden relative">

      {/* Visual Breathing Exercise Overlay */}
      <BreathingGuide phase={breathPhase} />

      {/* Main Conversation Area */}
      <div className="flex-1 flex flex-col min-w-0">
        <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-white z-20 shrink-0">
            <div className="flex items-center gap-3">
